window.ASBAB_NUZUL_CACHE["66"] = {"asbab_nuzul":{"1":[{"ar":"عن عَائِشَةَ رضي الله عنها قالت: أَنَّ النَّبِيَّ ﷺ كَانَ يَمْكُثُ عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ، وَيَشْرَبُ عِنْدَهَا عَسَلًا، فَتَوَاصَيْتُ أَنَا وَحَفْصَةُ: أَنَّ أَيَّتَنَا دَخَلَ عَلَيْهَا النَّبِيُّ ﷺ فَلْتَقُلْ: إِنِّي أَجِدُ مِنْكَ رِيحَ مَغَافِيرَ، أَكَلْتَ مَغَافِيرَ. فَدَخَلَ عَلَى إِحْدَاهُمَا فَقَالَتْ ذَلِكَ لَهُ، فَقَالَ: « لا، بَلْ شَرِبْتُ عَسَلًا عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ، وَلَنْ أَعُودَ لَهُ »، فَنَزَلَتْ: { يَـٰٓأَيُّهَا ٱلنَّبِىُّ لِمَ تُحَرِّمُ مَآ أَحَلَّ ٱللَّهُ لَكَ ۖ } { إِن تَتُوبَآ إِلَى ٱللَّهِ } لِعَائِشَةَ وَحَفْصَةَ. { وَإِذْ أَسَرَّ ٱلنَّبِىُّ إِلَىٰ بَعْضِ أَزْوَٰجِهِۦ حَدِيثًا }. لِقَوْلِهِ: « بَلْ شَرِبْتُ عَسَلًا »، وَقَالَ لِي إِبْرَاهِيمُ بْنُ مُوسَى، عَنْ هِشَامٍ: « وَلَنْ أَعُودَ لَهُ، وَقَدْ حَلَفْتُ، فَلَا تُخْبِرِي بِذَلِكِ أَحَداً ». واللفظ للبخاري.","id":""},{"ar":"عن ابن عباس رضي الله عنهما قال: كان رسول الله ﷺ يشرب عند سودة العسل، فدخل على عائشة، فقالت: إني أجد منك ريحاً، ثم دخل على حفصة، فقالت: إني أجد منك ريحاً فقال: « أراه من شراب شربته عند سودة، والله لا أشربه ». فنزلت هذه الآية { يَـٰٓأَيُّهَا ٱلنَّبِىُّ لِمَ تُحَرِّمُ مَآ أَحَلَّ ٱللَّهُ لَكَ ۖ }.","id":""}],"4":[{"ar":"عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ: قَالَ عُمَرُ بْنُ الْخَطَّابِ رضي الله عنه: (وَافَقْتُ رَبِّي فِي ثَلَاثٍ... ) (... وَاجْتَمَعَ نِسَاءُ النَّبِيِّ ﷺ فِي الْغَيْرَةِ عَلَيْهِ، فَقُلْتُ لَهُنَّ: { عَسَىٰ رَبُّهُۥٓ إِن طَلَّقَكُنَّ أَن يُبْدِلَهُۥٓ أَزْوَٰجًا خَيْرًا مِّنكُنَّ } فَنَزَلَتْ هَذِهِ الْآيةُ ).","id":""},{"ar":"عَنْ عَبْدِ اللهِ بْنِ عَبَّاسٍ رضي الله عنهما: حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ رضي الله عنه قَالَ: ( لَمَّا اعْتَزَلَ نَبِيُّ اللهِ ﷺ نِسَاءَهُ... ) (... وَدَخَلْتُ عَلَيْهِ حِينَ دَخَلْتُ، وَأَنَا أَرَى فِي وَجْهِهِ الْغَضَبَ، فَقُلْتُ: يَا رَسُولَ اللهِ، مَا يَشُقُّ عَلَيْكَ مِنْ شَأْنِ النِّسَاءِ، فَإِنْ كُنْتَ طَلَّقْتَهُنَّ، فَإِنَّ اللهَ مَعَكَ، وَمَلَائِكَتَهُ، وَجِبْرِيلَ، وَمِيكَائِيلَ وَأَنَا وَأَبُو بَكْرٍ، وَالْمُؤْمِنُونَ مَعَكَ. وَقَلَّمَا تَكَلَّمْتُ - وَأَحْمَدُ اللهَ - بِكَلَامٍ إِلَّا رَجَوْتُ أَنْ يَكُونَ اللهُ يُصَدِّقُ قَوْلِي الَّذِي أَقُولُ، وَنَزَلَتْ هَذِهِ الْآيَةُ آيَةُ التَّحْيِيرِ { عَسَىٰ رَبُّهُۥٓ إِن طَلَّقَكُنَّ أَن يُبْدِلَهُۥٓ أَزْوَٰجًا خَيْرًا مِّنكُنَّ }... { وَإِن تَظَـٰهَرَا عَلَيْهِ فَإِنَّ ٱللَّهَ هُوَ مَوْلَىٰهُ وَجِبْرِيلُ وَصَـٰلِحُ ٱلْمُؤْمِنِينَ ۖ وَٱلْمَلَـٰٓئِكَةُ بَعْدَ ذَٰلِكَ ظَهِيرٌ }.\n\nوَكَانَتْ عَائِشَةُ بِنْتُ أَبِي بَكْرٍ، وَحَفْصَةُ، تَظَاهَرَانِ عَلَى سَائِرِ نِسَاءِ النَّبِيِّ ﷺ، فَقُلْتُ: يَا رَسُولَ اللهِ، أَطَلَّقْتَهُنَّ؟ قَالَ: « لا »، قُلْتُ: يَا رَسُولَ اللهِ إِنِّي دَخَلْتُ الْمَسْجِدَ، وَالْمُسْلِمُونَ يَنْكُتُونَ بِالْحَصَى، يَقُولُونَ: طَلَّقَ رَسُولُ اللهِ ﷺ نِسَاءَهُ، أَفَأَنْزِلُ فَأُخْبِرَهُمْ أَنَّكَ لَمْ تُطَلِّقْهُنَّ؟ قَالَ: « نَعَمْ، إِنْ شِئْتَ ». فَلَمْ أَزَلْ أُحَدِّثُهُ حَتَّى تَحَسَّرَ الْغَضَبُ عَنْ وَجْهِهِ، وَحَتَّى كَشَرَ فَضَحِكَ، وَكَانَ مِنْ أَحْسَنِ النَّاسِ ثَغْراً.\n\nثُمَّ نَزَلَ نَبِيُّ اللهِ ﷺ وَنَزَلْتُ، فَنَزَلْتُ أَتَشَبَّثُ بِالْجِذْعِ، وَنَزَلَ رَسُولُ اللهِ ﷺ كَأَنَّمَا يَمْشِي عَلَى الْأَرْضِ مَا يَمَسُّهُ بِيَدِهِ، فَقُلْتُ: يَا رَسُولَ اللهِ، إِنَّمَا كُنْتَ فِي الْغُرْفَةِ تِسْعَةً وَعِشْرِينَ، قَالَ: « إِنَّ الشَّهْرَ يَكُونُ تِسْعاً وَعِشْرِينَ »، فَقُمْتُ عَلَى بَابِ الْمَسْجِدِ، فَنَادَيْتُ بِأَعْلَى صَوْتِي: لَمْ يُطَلِّقْ رَسُولُ اللهِ ﷺ نِسَاءَهُ، وَنَزَلَتْ هَذِهِ الْآيَةُ: { وَإِذَا جَآءَهُمْ أَمْرٌ مِّنَ ٱلْأَمْنِ أَوِ ٱلْخَوْفِ أَذَاعُوا۟ بِهِۦ ۖ وَلَوْ رَدُّوهُ إِلَى ٱلرَّسُولِ وَإِلَىٰٓ أُو۟لِى ٱلْأَمْرِ مِنْهُمْ لَعَلِمَهُ ٱلَّذِينَ يَسْتَنۢبِطُونَهُۥ مِنْهُمْ ۗ }، فَكُنْتُ أَنَا اسْتَنْبَطْتُ ذَلِكَ الْأَمْرَ وَأَنْزَلَ اللهُ عز و جل آيَةَ التَّخْيِيرِ. واللفظ لمسلم.","id":""}],"5":[{"ar":"عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ: قَالَ عُمَرُ بْنُ الْخَطَّابِ رضي الله عنه: (وَافَقْتُ رَبِّي فِي ثَلَاثٍ... ) (... وَاجْتَمَعَ نِسَاءُ النَّبِيِّ ﷺ فِي الْغَيْرَةِ عَلَيْهِ، فَقُلْتُ لَهُنَّ: { عَسَىٰ رَبُّهُۥٓ إِن طَلَّقَكُنَّ أَن يُبْدِلَهُۥٓ أَزْوَٰجًا خَيْرًا مِّنكُنَّ } فَنَزَلَتْ هَذِهِ الْآيةُ ).","id":""},{"ar":"عَنْ عَبْدِ اللهِ بْنِ عَبَّاسٍ رضي الله عنهما: حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابِ رضي الله عنه قَالَ: ( لَمَّا اعْتَزَلَ نَبِيُّ اللهِ ﷺ نِسَاءَهُ... ) (... وَدَخَلْتُ عَلَيْهِ حِينَ دَخَلْتُ، وَأَنَا أَرَى فِي وَجْهِهِ الْغَضَبَ، فَقُلْتُ: يَا رَسُولَ اللهِ، مَا يَشُقُّ عَلَيْكَ مِنْ شَأْنِ النِّسَاءِ، فَإِنْ كُنْتَ طَلَّقْتَهُنَّ، فَإِنَّ اللهَ مَعَكَ، وَمَلَائِكَتَهُ، وَجِبْرِيلَ، وَمِيكَائِيلَ وَأَنَا وَأَبُو بَكْرٍ، وَالْمُؤْمِنُونَ مَعَكَ. وَقَلَّمَا تَكَلَّمْتُ - وَأَحْمَدُ اللهَ - بِكَلَامٍ إِلَّا رَجَوْتُ أَنْ يَكُونَ اللهُ يُصَدِّقُ قَوْلِي الَّذِي أَقُولُ، وَنَزَلَتْ هَذِهِ الْآيَةُ آيَةُ التَّحْيِيرِ { عَسَىٰ رَبُّهُۥٓ إِن طَلَّقَكُنَّ أَن يُبْدِلَهُۥٓ أَزْوَٰجًا خَيْرًا مِّنكُنَّ }... { وَإِن تَظَـٰهَرَا عَلَيْهِ فَإِنَّ ٱللَّهَ هُوَ مَوْلَىٰهُ وَجِبْرِيلُ وَصَـٰلِحُ ٱلْمُؤْمِنِينَ ۖ وَٱلْمَلَـٰٓئِكَةُ بَعْدَ ذَٰلِكَ ظَهِيرٌ }.\n\nوَكَانَتْ عَائِشَةُ بِنْتُ أَبِي بَكْرٍ، وَحَفْصَةُ، تَظَاهَرَانِ عَلَى سَائِرِ نِسَاءِ النَّبِيِّ ﷺ، فَقُلْتُ: يَا رَسُولَ اللهِ، أَطَلَّقْتَهُنَّ؟ قَالَ: « لا »، قُلْتُ: يَا رَسُولَ اللهِ إِنِّي دَخَلْتُ الْمَسْجِدَ، وَالْمُسْلِمُونَ يَنْكُتُونَ بِالْحَصَى، يَقُولُونَ: طَلَّقَ رَسُولُ اللهِ ﷺ نِسَاءَهُ، أَفَأَنْزِلُ فَأُخْبِرَهُمْ أَنَّكَ لَمْ تُطَلِّقْهُنَّ؟ قَالَ: « نَعَمْ، إِنْ شِئْتَ ». فَلَمْ أَزَلْ أُحَدِّثُهُ حَتَّى تَحَسَّرَ الْغَضَبُ عَنْ وَجْهِهِ، وَحَتَّى كَشَرَ فَضَحِكَ، وَكَانَ مِنْ أَحْسَنِ النَّاسِ ثَغْراً.\n\nثُمَّ نَزَلَ نَبِيُّ اللهِ ﷺ وَنَزَلْتُ، فَنَزَلْتُ أَتَشَبَّثُ بِالْجِذْعِ، وَنَزَلَ رَسُولُ اللهِ ﷺ كَأَنَّمَا يَمْشِي عَلَى الْأَرْضِ مَا يَمَسُّهُ بِيَدِهِ، فَقُلْتُ: يَا رَسُولَ اللهِ، إِنَّمَا كُنْتَ فِي الْغُرْفَةِ تِسْعَةً وَعِشْرِينَ، قَالَ: « إِنَّ الشَّهْرَ يَكُونُ تِسْعاً وَعِشْرِينَ »، فَقُمْتُ عَلَى بَابِ الْمَسْجِدِ، فَنَادَيْتُ بِأَعْلَى صَوْتِي: لَمْ يُطَلِّقْ رَسُولُ اللهِ ﷺ نِسَاءَهُ، وَنَزَلَتْ هَذِهِ الْآيَةُ: { وَإِذَا جَآءَهُمْ أَمْرٌ مِّنَ ٱلْأَمْنِ أَوِ ٱلْخَوْفِ أَذَاعُوا۟ بِهِۦ ۖ وَلَوْ رَدُّوهُ إِلَى ٱلرَّسُولِ وَإِلَىٰٓ أُو۟لِى ٱلْأَمْرِ مِنْهُمْ لَعَلِمَهُ ٱلَّذِينَ يَسْتَنۢبِطُونَهُۥ مِنْهُمْ ۗ }، فَكُنْتُ أَنَا اسْتَنْبَطْتُ ذَلِكَ الْأَمْرَ وَأَنْزَلَ اللهُ عز و جل آيَةَ التَّخْيِيرِ. واللفظ لمسلم.","id":""}]},"mapping_ayat":{"66:4":[{"p":"Bukhari","n":2288,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمْ أَزَلْ حَرِيصًا عَلَى أَنْ أَسْأَلَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }فَحَجَجْتُ مَعَه فَعَدَلَ وَعَدَلْتُ مَعَهُ بِالْإِدَاوَةِ فَتَبَرَّزَ حَتَّى جَاءَ فَسَكَبْتُ عَلَى يَدَيْهِ مِنْ الْإِدَاوَةِ فَتَوَضَّأَ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ الْمَرْأَتَانِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَانِ قَالَ اللَّهُ عَزَّ وَجَلَّ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }فَقَالَ وَا عَجَبِي لَكَ يَا ابْنَ عَبَّاسٍ عَائِشَةُ وَحَفْصَةُ ثُمَّ اسْتَقْبَلَ عُمَرُ الْحَدِيثَ يَسُوقُهُ فَقَالَ إِنِّي كُنْتُ وَجَارٌ لِي مِنْ الْأَنْصَارِ فِي بَنِي أُمَيَّةَ بْنِ زَيْدٍ وَهِيَ مِنْ عَوَالِي الْمَدِينَةِ وَكُنَّا نَتَنَاوَبُ النُّزُولَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْزِلُ يَوْمًا وَأَنْزِلُ يَوْمًا فَإِذَا نَزَلْتُ جِئْتُهُ مِنْ خَبَرِ ذَلِكَ الْيَوْمِ مِنْ الْأَمْرِ وَغَيْرِهِ وَإِذَا نَزَلَ فَعَلَ مِثْلَهُ وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا عَلَى الْأَنْصَارِ إِذَا هُمْ قَوْمٌ تَغْلِبُهُمْ نِسَاؤُهُمْ فَطَفِقَ نِسَاؤُنَا يَأْخُذْنَ مِنْ أَدَبِ نِسَاءِ الْأَنْصَارِ فَصِحْتُ عَلَى امْرَأَتِي فَرَاجَعَتْنِي فَأَنْكَرْتُ أَنْ تُرَاجِعَنِي فَقَالَتْ وَلِمَ تُنْكِرُ أَنْ أُرَاجِعَكَ فَوَاللَّهِ إِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ليُرَاجِعْنَهُ وَإِنَّ إِحْدَاهُنَّ لَتَهْجُرُهُ الْيَوْمَ حَتَّى اللَّيْلِ فَأَفْزَعَنِي فَقُلْتُ خَابَتْ مَنْ فَعَلَ مِنْهُنَّ بِعَظِيمٍ ثُمَّ جَمَعْتُ عَلَيَّ ثِيَابِي فَدَخَلْتُ عَلَى حَفْصَةَ فَقُلْتُ أَيْ حَفْصَةُ أَتُغَاضِبُ إِحْدَاكُنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَوْمَ حَتَّى اللَّيْلِ فَقَالَتْ نَعَمْ فَقُلْتُ خَابَتْ وَخَسِرَتْ أَفَتَأْمَنُ أَنْ يَغْضَبَ اللَّهُ لِغَضَبِ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَهْلِكِينَ لَا تَسْتَكْثِرِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تُرَاجِعِيهِ فِي شَيْءٍ وَلَا تَهْجُرِيهِ وَاسْأَلِينِي مَا بَدَا لَكِ وَلَا يَغُرَّنَّكِ أَنْ كَانَتْ جَارَتُكَ هِيَ أَوْضَأَ مِنْكِ وَأَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عَائِشَةَ وَكُنَّا تَحَدَّثْنَا أَنَّ غَسَّانَ تُنْعِلُ النِّعَالَ لِغَزْوِنَا فَنَزَلَ صَاحِبِي يَوْمَ نَوْبَتِهِ فَرَجَعَ عِشَاءً فَضَرَبَ بَابِي ضَرْبًا شَدِيدًا وَقَالَ أَنَائِمٌ هُوَ فَفَزِعْتُ فَخَرَجْتُ إِلَيْهِ وَقَالَ حَدَثَ أَمْرٌ عَظِيمٌ قُلْتُ مَا هُوَ أَجَاءَتْ غَسَّانُ قَالَ لَا بَلْ أَعْظَمُ مِنْهُ وَأَطْوَلُ طَلَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ قَالَ قَدْ خَابَتْ حَفْصَةُ وَخَسِرَتْ كُنْتُ أَظُنُّ أَنَّ هَذَا يُوشِكُ أَنْ يَكُونَ فَجَمَعْتُ عَلَيَّ ثِيَابِي فَصَلَّيْتُ صَلَاةَ الْفَجْرِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ مَشْرُبَةً لَهُ فَاعْتَزَلَ فِيهَا فَدَخَلْتُ عَلَى حَفْصَةَ فَإِذَا هِيَ تَبْكِي قُلْتُ مَا يُبْكِيكِ أَوَلَمْ أَكُنْ حَذَّرْتُكِ أَطَلَّقَكُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَا أَدْرِي هُوَ ذَا فِي الْمَشْرُبَةِ فَخَرَجْتُ فَجِئْتُ الْمِنْبَرَ فَإِذَا حَوْلَهُ رَهْطٌ يَبْكِي بَعْضُهُمْ فَجَلَسْتُ مَعَهُمْ قَلِيلًا ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ الْمَشْرُبَةَ الَّتِي هُوَ فِيهَا فَقُلْتُ لِغُلَامٍ لَهُ أَسْوَدَ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ فَكَلَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ خَرَجَ فَقَالَ ذَكَرْتُكَ لَهُ فَصَمَتَ فَانْصَرَفْتُ حَتَّى جَلَسْتُ مَعَ الرَّهْطِ الَّذِينَ عِنْدَ الْمِنْبَرِ ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ فَذَكَرَ مِثْلَهُ فَجَلَسْتُ مَعَ الرَّهْطِ الَّذِينَ عِنْدَ الْمِنْبَرِ ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ الْغُلَامَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ فَذَكَرَ مِثْلَهُ فَلَمَّا وَلَّيْتُ مُنْصَرِفًا فَإِذَا الْغُلَامُ يَدْعُونِي قَالَ أَذِنَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلْتُ عَلَيْهِ فَإِذَا هُوَ مُضْطَجِعٌ عَلَى رِمَالِ حَصِيرٍ لَيْسَ بَيْنَهُ وَبَيْنَهُ فِرَاشٌ قَدْ أَثَّرَ الرِّمَالُ بِجَنْبِهِ مُتَّكِئٌ عَلَى وِسَادَةٍ مِنْ أَدَمٍ حَشْوُهَا لِيفٌ فَسَلَّمْتُ عَلَيْهِ ثُمَّ قُلْتُ وَأَنَا قَائِمٌ طَلَّقْتَ نِسَاءَكَ فَرَفَعَ بَصَرَهُ إِلَيَّ فَقَالَ لَا ثُمَّ قُلْتُ وَأَنَا قَائِمٌ أَسْتَأْنِسُ يَا رَسُولَ اللَّهِ لَوْ رَأَيْتَنِي وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا عَلَى قَوْمٍ تَغْلِبُهُمْ نِسَاؤُهُمْ فَذَكَرَهُ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قُلْتُ لَوْ رَأَيْتَنِي وَدَخَلْتُ عَلَى حَفْصَةَ فَقُلْتُ لَا يَغُرَّنَّكِ أَنْ كَانَتْ جَارَتُكِ هِيَ أَوْضَأَ مِنْكِ وَأَحَبَّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عَائِشَةَ فَتَبَسَّمَ أُخْرَى فَجَلَسْتُ حِينَ رَأَيْتُهُ تَبَسَّمَ ثُمَّ رَفَعْتُ بَصَرِي فِي بَيْتِهِ فَوَاللَّهِ مَا رَأَيْتُ فِيهِ شَيْئًا يَرُدُّ الْبَصَرَ غَيْرَ أَهَبَةٍ ثَلَاثَةٍ فَقُلْتُ ادْعُ اللَّهَ فَلْيُوَسِّعْ عَلَى أُمَّتِكَ فَإِنَّ فَارِسَ وَالرُّومَ وُسِّعَ عَلَيْهِمْ وَأُعْطُوا الدُّنْيَا وَهُمْ لَا يَعْبُدُونَ اللَّهَ وَكَانَ مُتَّكِئًا فَقَالَ أَوَفِي شَكٍّ أَنْتَ يَا ابْنَ الْخَطَّابِ أُولَئِكَ قَوْمٌ عُجِّلَتْ لَهُمْ طَيِّبَاتُهُمْ فِي الْحَيَاةِ الدُّنْيَا فَقُلْتُ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ لِي فَاعْتَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَجْلِ ذَلِكَ الْحَدِيثِ حِينَ أَفْشَتْهُ حَفْصَةُ إِلَى عَائِشَةَ وَكَانَ قَدْ قَالَ مَا أَنَا بِدَاخِلٍ عَلَيْهِنَّ شَهْرًا مِنْ شِدَّةِ مَوْجِدَتِهِ عَلَيْهِنَّ حِينَ عَاتَبَهُ اللَّهُ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ دَخَلَ عَلَى عَائِشَةَ فَبَدَأَ بِهَا فَقَالَتْ لَهُ عَائِشَةُ إِنَّكَ أَقْسَمْتَ أَنْ لَا تَدْخُلَ عَلَيْنَا شَهْرًا وَإِنَّا أَصْبَحْنَا لِتِسْعٍ وَعِشْرِينَ لَيْلَةً أَعُدُّهَا عَدًّا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ وَكَانَ ذَلِكَ الشَّهْرُ تِسْعًا وَعِشْرِينَ قَالَتْ عَائِشَةُ فَأُنْزِلَتْ آيَةُ التَّخْيِيرِ فَبَدَأَ بِي أَوَّلَ امْرَأَةٍ فَقَالَ إِنِّي ذَاكِرٌ لَكِ أَمْرًا وَلَا عَلَيْكِ أَنْ لَا تَعْجَلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ قَدْ أَعْلَمُ أَنَّ أَبَوَيَّ لَمْ يَكُونَا يَأْمُرَانِي بِفِرَاقِكَ ثُمَّ قَالَ إِنَّ اللَّهَ قَالَ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ إِلَى قَوْلِهِ عَظِيمًا }قُلْتُ أَفِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ ثُمَّ خَيَّرَ نِسَاءَهُ فَقُلْنَ مِثْلَ مَا قَالَتْ عَائِشَةُ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku ['Ubaidullah bin 'Abdullah bin Abu Tsaur] dari ['Abdullah bin 'Abbas radliallahu 'anhuma] berkata: \"Aku selalu antusias untuk bertanya kepada ['Umar] tentang dua wanita diantara isteri-isteri Nabi shallallahu 'alaihi wasallam yang Allah berfirman kepada keduanya: (\"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan) …QS At-Tahrim 4). Maka aku kunjungi dia namun dia menghindar dan aku susul dia dengan membawa kantong terbuat dari kulit berisi air hingga dia datang, lalu aku tuangkan air dari kantong air tadi keatas kedua tangannya hingga dia berwudhu' lalu aku tanya: \"Wahai amirul mu'minin, siapakah dua wanita dari isteri Nabi shallallahu 'alaihi wasallam yang Allah berfirman kepadanya (\"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan) …), maka dia menjawab: \"Aku heran kepadamu wahai Ibnu 'Abbas!, dia adalah 'Aisyah dan Hafshah\". Kemudian 'Umar menyebutkan hadits, katanya: \"Aku dan tetanggaku dari Anshar berada di desa Banu Umayyah bin Zaid, termasuk suku kepercayaan di Madinah dan kami saling bergantian menemui Rasul shallallahu 'alaihi wasallam. Sehari aku yang menemui Beliau shallallahu 'alaihi wasallam, hari lain dia yang menemui Beliau shallallahu 'alaihi wasallam. Jika giliranku menemui Beliau, aku menanyakan seputar wahyu yang turun hari itu dan perkara lainnya. Dan jika giliran tetangguku itu, ia pun melakukan hal sama. Kami adalah kaum Quraisy yang bisa menundukkan para isteri, hingga ketika kami mendatangi Kaum Anshar, ternyata mereka adalah sebuah kaum yang ditundukkan oleh isteri-isteri mereka. Lalu isteri-isteri kami segera saja meniru kebiasaan wanita Anshar tersebut. Suatu hari aku nasehati isteriku tapi dia membantahku dan aku larang dia membantahku tapi dia berkata: \"Kenapa kamu melarang aku membantahmu? Demi Allah, sesungguhnya hari ini isteri-isteri Nabi Shallallahu 'alaihiwasallam telah membantah Beliau bahkan seorang dari mereka tidak berbicara kepada Beliau hingga malam hari\". Aku kaget mendengar itu lalu aku katakan: \"Sangat celakalah diantara kalian orang yang berbuat hal seperti ini\". Kemudian aku bergegas untuk menemui Hafshah lalu aku bertanya: \"Wahai Hafshah, apakah salah seorang dari kalian hari ini telah membantah Rasulullah shallallahu 'alaihi wasallam hingga malam hari?\" Dia menjawab: \"Iya\". Aku katakan: \"Celaka dan rugilah. Apakah kalian merasa aman dari murka Allah disebabkan RasulNya shallallahu 'alaihi wasallam marah lalu kalian menjadi binasa? Janganlah kalian menuntut terlalu banyak kepada Rasulullah shallallahu 'alaihi wasallam dan jangan kalian membantahnya tentang suatu apapun dan jangan pula kalian menghindar untuk berbicara dengan Beliau. Mintalah kepadaku apa yang menjadi keperluanmu dan jangan kamu cemburu bila ada (isteri Nabi shallallahu 'alaihi wasallam), madu kamu, yang lebih cantik dan lebih dicintai oleh Rasulullah shallallahu 'alaihi wasallam \". Yang dimaksudkannya adalah 'Aisyah radliallahu 'anha. Suatu hari kami membicarakan suku Ghossan sebagai tukang sepatu yang biasanya menyiapkan sepatu kami untuk perang. Maka sahabatku pergi (menemui Rasulullah shallallahu 'alaihi wasallam) pada hari gilirannya lalu dia kembali pada waktu 'Isya dengan mengetuk rumahku dengan sangat keras seraya berkata: \"Apakah dia sudah tidur?\" Aku kaget lalu keluar menemuinya. Dia berkata: \"Telah terjadi masalah besar\". Aku bertanya: \"Masalah apa itu? Apakah suku Ghassan sudah datang?\" Dia menjawab: \"Bukan, bahkan urusannya lebih penting dan lebih panjang dari masalah itu. Rasulullah shallallahu 'alaihi wasallam telah menceraikan isteri-isteri Beliau. 'Umar berkata: \"Sungguh celaka dan rugilah Hafshah. Aku mengira hal ini tidak akan terjadi. Maka aku lipat pakaianku kemudian aku shalat Shubuh bersama Nabi shallallahu 'alaihi wasallam lalu Beliau memasuki bilik yang tinggi dan mengasingkan diri disana. Maka aku menemui Hafshah yang ternyata sedang menangis lalu aku bertanya: \"Apa yang membuatmu menangis, bukankah aku sudah peringatkan kamu? Apakah Rasulullah shallallahu 'alaihi wasallam telah menceraikan kalian?\" Dia menjawab: \"Aku tidak tahu, sekarang Beliau berada di tempat pengasingannya\". Maka aku keluar lalu mendatangi mimbar ternyata di sekelilingnya ada sejumlah orang (kurang dari sepuluh) yang sedang berkumpul diantaranya ada yang menangis. Maka aku duduk bersama mereka sebentar lalu aku sangat ingin mendatangi tempat pengasingan tempat Beliau berdiam disana. Aku katakan kepada Aswad, anak kecil pembantu Beliau: \"Mintakanlah izin untuk 'Umar?\" Maka dia masuk dan berbicara dengan Nabi shallallahu 'alaihi wasallam lalu keluar dan berkata: \"Aku sudah sampaikan tentang maksudmu namun Beliau diam saja\". Maka kemudian aku kembali dan berkumpul bersama orang-orang yang berada dekat mimbar. Sesaat kemudian timbul lagi keinginanku maka aku temui anak kecil itu lalu aku sampaikan maksudku seperti tadi dan diapun menjawab seperti tadi pula. Maka aku kembali duduk bersama orang-orang yang berada dekat mimbar. Ternyata timbul lagi keinginanku, maka aku datangi lagi anak kecil itu dan aku katakan: \"Mintakanlah izin untuk 'Umar?\" Maka dia menjawab seperti tadi pula. Ketika aku hendak kembali, anak kecil itu memanggilku dan berkata: \"Rasulullah shallallahu 'alaihi wasallam mengizinkan kamu masuk\". Maka aku masuk menemui Beliau yang ketika itu Beliau sedang berbaring diatas pasir sebagai kasurnya, dan tidak ada kasur yang menengahi antara pasir dan beliau sehingga pasir itu membekas pada sisi badan Beliau, Beliau bersandar diatas bantal yang terbuat dari kulit yang isinya sabut. Aku memberi salam kepada Beliau lalu aku berkata dalam posisi tetap berdiri: \"Apakah anda telah menceraikan isteri-isteri anda\". Maka Beliau memandang ke arahku lalu berkata: \"Tidak\". Kemudian aku katakan: \"Apakah anda merasa tidak enak karena melihat aku?\" Kami ini adalah orang Quraisy yang biasa menundukkan isteri-isteri. Ketika kami datang disini bertemu dengan Kaum yang mereka ditundukkan oleh isteri-isteri mereka\". Maka 'Umar menceritakan. Lalu Nabi shallallahu 'alaihi wasallam tersenyum. Kemudian aku katakan: \"Bagaimana seandainya anda melihatku menemui Hafshah dan aku katakan kepadanya: \"Jangan kamu cemburu bila ada (isteri Nabi shallallahu 'alaihi wasallam), madu kamu, yang lebih cantik dan lebih dicintai oleh Rasulullah shallallahu 'alaihi wasallam \". Yang dimaksudkan Umar adalah 'Aisyah radliallahu 'anha. Maka Beliau tersenyum lagi. Lalu aku duduk ketika melihat Beliau tersenyum lalu aku memandang ke rumah Beliau. Demi Allah, aku tidak melihat apapun disana, karena mataku bolak balik melihat tidak kurang dari tiga kali. Lalu aku katakan: \"Mintalah kepada Allah agar melapangkan dunia buat ummat anda karena bangsa Persia dan Ramawi saja dilapangkan dan diberikan dunia padahal mereka tidak menyembah Allah\". Saat itu Beliau sedang berbaring lalu berkata: \"Apakah kamu ragu wahai Ibnu Al Khaththob? Mereka itulah kaum yang telah disegerakan kebaikan mereka dalam kehidupan dunia ini\". Aku katakan: \"Wahai Rasulullah, mohonkanlah ampun buatku\". Ternyata disebabkan kalimatku seperti tadilah Rasulullah shallallahu 'alaihi wasallam mengasingkan diri ketika Hafshah menyampaikannya kepada 'Aisyah radliallahu 'anha. Sebelumnya Beliau telah berkata: Aku tidak akan tinggal bersama mereka selama satu bulan karena disebabkan kesalnya Beliau terhadap mereka setelah Allah menegur Beliau. Ketika telah berlalu masa selama dua puluh sembilan hari, yang pertama kali Beliau datangi adalah 'Aisyah. Maka 'Aisyah berkata, kepada Beliau: \"Anda sudah bersumpah untuk tidak mendatangi kami selama satu bulan, sedangkan hari ini kita baru melewati malam kedua puluh sembilan, aku sudah menghitungnya\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Bulan ini berjumlah dua puluh sembilan hari\". Pada bulan itu memang berjumlah dua puluh sembilan hari. Kemudian 'Aisyah radliallahu 'anha berkata: \"Maka turunlah ayat takhyiir (pilihan). Maka Beliau memulainya dari aku sebagai yang pertama dari isteri-isteri Beliau. Beliau berkata: \"Sesungguhnya aku mengingatkan kamu pada suatu urusan yaitu janganlah kamu tergesa-gesa hingga kamu meminta pendapat kedua orangtuamu\". 'Aisyah radliallahu 'anha berkata: \"Aku sudah mengetahui bahwa kedua orangtuaku tidaklah menyuruh aku untuk bercerai dari anda\" Kemudian Beliau berkata: \"Sesungguhnya Allah telah berfirman: (\"Wahai Nabi, katakanlah kepada isteri-isterimu … hingga sampai pada firmanNya … pahala yang besar) QS Al Ahzab: 28 -29). Aisyah radliallahu 'anha berkata: \"Apakah begitu kedua orangtuaku memerintahkannya? Sungguh aku lebih memilih Allah, RasulNya dan kehidupan akhirat\". Kemudian para isteri Beliau memilih hal yang sama lalu mereka berkata, seperti yang diucapkan 'Aisyah radliallahu 'anha."},{"p":"Nasa'i","n":2058,"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ حَدَّثَهُ ح و أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمْ أَزَلْ حَرِيصًا أَنْ أَسْأَلَ عُمَرَ بْنَ الْخَطَّابِ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }وَسَاقَ الْحَدِيثَ وَقَالَ فِيهِ فَاعْتَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ مِنْ أَجْلِ ذَلِكَ الْحَدِيثِ حِينَ أَفْشَتْهُ حَفْصَةُ إِلَى عَائِشَةَ تِسْعًا وَعِشْرِينَ لَيْلَةً قَالَتْ عَائِشَةُ وَكَانَ قَالَ مَا أَنَا بِدَاخِلٍ عَلَيْهِنَّ شَهْرًا مِنْ شِدَّةِ مَوْجِدَتِهِ عَلَيْهِنَّ حِينَ حَدَّثَهُ اللَّهُ عَزَّ وَجَلَّ حَدِيثَهُنَّ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ لَيْلَةً دَخَلَ عَلَى عَائِشَةَ فَبَدَأَ بِهَا فَقَالَتْ لَهُ عَائِشَةُ إِنَّكَ قَدْ كُنْتَ آلَيْتَ يَا رَسُولَ اللَّهِ أَنْ لَا تَدْخُلَ عَلَيْنَا شَهْرًا وَإِنَّا أَصْبَحْنَا مِنْ تِسْعٍ وَعِشْرِينَ لَيْلَةً نَعُدُّهَا عَدَدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ لَيْلَةً","trj":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami, dari [Shalih] dari [Ibnu Syihab] bahwasanya ['Ubaidullah bin 'Abdullah bin Abu Tsaur] menceritakan kepadanya. Demikian juga diriwayatkan dari jalur lain, dan telah mengabarkan kepada kami ['Amru bin Manshur] dia berkata; telah menceritakan kepada kami [Al Hakam bin Nafi'] dia berkata; telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin Abu Tsaur] dari [Ibnu 'Abbas] dia berkata; Aku masih tetap bersemangat untuk bertanya kepada [Umar bin Khaththab] tentang dua orang dari istri Rasulullah shallallahu 'alaihi wasallam yang Allah berfirman kepada keduanya: \"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong -untuk menerima kebaikan-.\" (Qs. At Tahrim 66: 4). Dan ia menyebutkan hadits ini. Ia berkata di dalam hadits tersebut; \"Maka Rasulullah shallallahu 'alaihi wasallam menjauh dari istri-istrinya karena pembicaraan itu; ketika Hafshah menyebarkannya kepada Aisyah, yaitu selama dua puluh Sembilan malam. Aisyah berkata; Beliau bersabda: \"Aku tidak akan menemui mereka selama satu bulan.\" Karena besarnya kemarahan beliau terhadap mereka, ketika Allah -Azza wa Jalla- menceritakan kepada beliau apa yang terjadi pada mereka. Setelah dua puluh Sembilan malam berlalu, beliau masuk menemui Aisyah, dan dengannyalah beliau memulainya, kemudian Aisyah berkata kepada beliau; \"Sesungguhnya engkau telah bersumpah wahai Rasulullah shallallahu 'alaihi wasallam, untuk tidak menemui kami selama satu bulan, dan kami memasuki pagi hari dari dua puluh sembilan malam, kami menghitungnya dari awal, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu ada dua puluh sembilan malam.\""},{"p":"Tirmidzi","n":3069,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ قَال سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُلَمْ أَزَلْ حَرِيصًا أَنْ أَسْأَلَ عُمَرَ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ عَزَّ وَجَلَّ{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }حَتَّى حَجَّ عُمَرُ وَحَجَجْتُ مَعَهُ فَصَبَبْتُ عَلَيْهِ مِنْ الْإِدَاوَةِ فَتَوَضَّأَ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ الْمَرْأَتَانِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَانِ قَالَ اللَّهُ{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا وَإِنْ تَظَاهَرَا عَلَيْهِ فَإِنَّ اللَّهَ هُوَ مَوْلَاهُ }فَقَالَ لِي وَاعَجَبًا لَكَ يَا ابْنَ عَبَّاسٍ قَالَ الزُّهْرِيُّ وَكَرِهَ وَاللَّهِ مَا سَأَلَهُ عَنْهُ وَلَمْ يَكْتُمْهُ فَقَالَ هِيَ عَائِشَةُ وَحَفْصَةُ قَالَ ثُمَّ أَنْشَأَ يُحَدِّثُنِي الْحَدِيثَ فَقَالَ كُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا الْمَدِينَةَ وَجَدْنَا قَوْمًا تَغْلِبُهُمْ نِسَاؤُهُمْ فَطَفِقَ نِسَاؤُنَا يَتَعَلَّمْنَ مِنْ نِسَائِهِمْ فَتَغَضَّبْتُ عَلَى امْرَأَتِي يَوْمًا فَإِذَا هِيَ تُرَاجِعُنِي فَقَالَتْ مَا تُنْكِرُ مِنْ ذَلِكَ فَوَاللَّهِ إِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُرَاجِعْنَهُ وَتَهْجُرُهُ إِحْدَاهُنَّ الْيَوْمَ إِلَى اللَّيْلِ قَالَ فَقُلْتُ فِي نَفْسِي قَدْ خَابَتْ مَنْ فَعَلَتْ ذَلِكَ مِنْهُنَّ وَخَسِرَتْ قَالَ وَكَانَ مَنْزِلِي بِالْعَوَالِي فِي بَنِي أُمَيَّةَ وَكَانَ لِي جَارٌ مِنْ الْأَنْصَارِ كُنَّا نَتَنَاوَبُ النُّزُولَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْزِلُ يَوْمًا فَيَأْتِينِي بِخَبَرِ الْوَحْيِ وَغَيْرِهِ وَأَنْزِلُ يَوْمًا فَآتِيهِ بِمِثْلِ ذَلِكَ قَالَ وَكُنَّا نُحَدِّثُ أَنَّ غَسَّانَ تُنْعِلُ الْخَيْلَ لِتَغْزُوَنَا قَالَ فَجَاءَنِي يَوْمًا عِشَاءً فَضَرَبَ عَلَى الْبَابِ فَخَرَجْتُ إِلَيْهِ فَقَالَ حَدَثَ أَمْرٌ عَظِيمٌ قُلْتُ أَجَاءَتْ غَسَّانُ قَالَ أَعْظَمُ مِنْ ذَلِكَ طَلَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ قَالَ فَقُلْتُ فِي نَفْسِي قَدْ خَابَتْ حَفْصَةُ وَخَسِرَتْ قَدْ كُنْتُ أَظُنُّ هَذَا كَائِنًا قَالَ فَلَمَّا صَلَّيْتُ الصُّبْحَ شَدَدْتُ عَلَيَّ ثِيَابِي ثُمَّ انْطَلَقْتُ حَتَّى دَخَلْتُ عَلَى حَفْصَةَ فَإِذَا هِيَ تَبْكِي فَقُلْتُ أَطَلَّقَكُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَا أَدْرِي هُوَ ذَا مُعْتَزِلٌ فِي هَذِهِ الْمَشْرَبَةِ قَالَ فَانْطَلَقْتُ فَأَتَيْتُ غُلَامًا أَسْوَدَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ قَالَ فَدَخَلَ ثُمَّ خَرَجَ إِلَيَّ قَالَ قَدْ ذَكَرْتُكَ لَهُ فَلَمْ يَقُلْ شَيْئًا قَالَ فَانْطَلَقْتُ إِلَى الْمَسْجِدِ فَإِذَا حَوْلَ الْمِنْبَرِ نَفَرٌ يَبْكُونَ فَجَلَسْتُ إِلَيْهِمْ ثُمَّ غَلَبَنِي مَا أَجِدُ فَأَتَيْتُ الْغُلَامَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ ثُمَّ خَرَجَ إِلَيَّ فَقَالَ قَدْ ذَكَرْتُكَ لَهُ فَلَمْ يَقُلْ شَيْئًا قَالَ فَانْطَلَقْتُ إِلَى الْمَسْجِدِ أَيْضًا فَجَلَسْتُ ثُمَّ غَلَبَنِي مَا أَجِدُ فَأَتَيْتُ الْغُلَامَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ ثُمَّ خَرَجَ إِلَيَّ فَقَالَ قَدْ ذَكَرْتُكَ لَهُ فَلَمْ يَقُلْ شَيْئًا قَالَ فَوَلَّيْتُ مُنْطَلِقًا فَإِذَا الْغُلَامُ يَدْعُونِي فَقَالَ ادْخُلْ فَقَدْ أُذِنَ لَكَ فَدَخَلْتُ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئٌ عَلَى رَمْلِ حَصِيرٍ قَدْ رَأَيْتُ أَثَرَهُ فِي جَنْبَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَطَلَّقْتَ نِسَاءَكَ قَالَ لَا قُلْتُ اللَّهُ أَكْبَرُ لَقَدْ رَأَيْتُنَا يَا رَسُولَ اللَّهِ وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا الْمَدِينَةَ وَجَدْنَا قَوْمًا تَغْلِبُهُمْ نِسَاؤُهُمْ فَطَفِقَ نِسَاؤُنَا يَتَعَلَّمْنَ مِنْ نِسَائِهِمْ فَتَغَضَّبْتُ يَوْمًا عَلَى امْرَأَتِي فَإِذَا هِيَ تُرَاجِعُنِي فَأَنْكَرْتُ ذَلِكَ فَقَالَتْ مَا تُنْكِرُ فَوَاللَّهِ إِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُرَاجِعْنَهُ وَتَهْجُرُهُ إِحْدَاهُنَّ الْيَوْمَ إِلَى اللَّيْلِ قَالَ فَقُلْتُ لِحَفْصَةَ أَتُرَاجِعِينَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ نَعَمْ وَتَهْجُرُهُ إِحْدَانَا الْيَوْمَ إِلَى اللَّيْلِ فَقُلْتُ قَدْ خَابَتْ مَنْ فَعَلَتْ ذَلِكَ مِنْكُنَّ وَخَسِرَتْ أَتَأْمَنُ إِحْدَاكُنَّ أَنْ يَغْضَبَ اللَّهُ عَلَيْهَا لِغَضَبِ رَسُولِهِ فَإِذَا هِيَ قَدْ هَلَكَتْ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقُلْتُ لِحَفْصَةَ لَا تُرَاجِعِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تَسْأَلِيهِ شَيْئًا وَسَلِينِي مَا بَدَا لَكِ وَلَا يَغُرَّنَّكِ إِنْ كَانَتْ صَاحِبَتُكِ أَوْسَمَ مِنْكِ وَأَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَتَبَسَّمَ أُخْرَى فَقُلْتُ يَا رَسُولَ اللَّهِ أَسْتَأْنِسُ قَالَ نَعَمْ قَالَ فَرَفَعْتُ رَأْسِي فَمَا رَأَيْتُ فِي الْبَيْتِ إِلَّا أُهُبَةً ثَلَاثَةً قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يُوَسِّعَ عَلَى أُمَّتِكَ فَقَدْ وَسَّعَ عَلَى فَارِسَ وَالرُّومِ وَهُمْ لَا يَعْبُدُونَهُ فَاسْتَوَى جَالِسًا فَقَالَ أَفِي شَكٍّ أَنْتَ يَا ابْنَ الْخَطَّابِ أُولَئِكَ قَوْمٌ عُجِّلَتْ لَهُمْ طَيِّبَاتُهُمْ فِي الْحَيَاةِ الدُّنْيَا قَالَ وَكَانَ أَقْسَمَ أَنْ لَا يَدْخُلَ عَلَى نِسَائِهِ شَهْرًا فَعَاتَبَهُ اللَّهُ فِي ذَلِكَ وَجَعَلَ لَهُ كَفَّارَةَ الْيَمِينِقَالَ الزُّهْرِيُّ فَأَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ قَالَتْ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ دَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَأَ بِي قَالَ يَا عَائِشَةُ إِنِّي ذَاكِرٌ لَكِ شَيْئًا فَلَا تَعْجَلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ }الْآيَةَ قَالَتْ عَلِمَ وَاللَّهِ أَنَّ أَبَوَيَّ لَمْ يَكُونَا يَأْمُرَانِي بِفِرَاقِهِ فَقُلْتُ أَفِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ قَالَ مَعْمَرٌ فَأَخْبَرَنِي أَيُّوبُ أَنَّ عَائِشَةَ قَالَتْ لَهُ يَا رَسُولَ اللَّهِ لَا تُخْبِرْ أَزْوَاجَكَ أَنِّي اخْتَرْتُكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا بَعَثَنِي اللَّهُ مُبَلِّغًا وَلَمْ يَبْعَثْنِي مُتَعَنِّتًا قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ ابْنِ عَبَّاسٍ","trj":"Telah menceritakan kepada kami [Abdu bin Humaid] telah mengabarkan kepada kami [Abdur Razzaq] dari [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abudullah bin Abu Tsaur], ia berkata; saya mendengar [Ibnu Abbas radliallahu 'anhuma] berkata; senantiasa aku bersemangat untuk bertanya kepada [Umar] mengenai dua orang wanita dari isteri-isteri Nabi shallallahu 'alaihi wasallam yang Allah dikatakan Allah 'azza wajalla: \"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan).\" (QS. Attahrim 4), Hingga Umar melakukan haji dan akupun berhaji bersamanya, kemudian aku menuangkan air dari tempat air untuk bersuci lalu ia berwudhu. Aku katakan; wahai amirul mukminin; siapakah dua orang wanita diantara isteri Nabi shallallahu 'alaihi wasallam yang Allah katakan: \"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan).\" (QS. Attahrim 4), Kemudian Umar berkata kepadaku; aneh engkau wahai Ibnu Abbas. Az Zuhri berkata; demi Allah ia tidak senang dengan apa yang ia tanyakan namun ia tidak menyembunyikannya. Ia berkata; ia adalah Aisyah dan Hafshah. Ibnu Abbas berkata; kemudian ia mulai menceritakan sebuah hadits kepadaku, ia berkata; dahulu kami orang-orang Quraisy menguasai para isteri, kemudian setelah kami datang ke Madinah kami mendapati orang-orang justru malah di atur para isteri mereka. Kemudian para isteri kami mulai belajar dari para isteri mereka, maka aku marah kepada isteriku pada suatu hari ternyata ia mendebatku dan berkata; apa yang engkau ingkari dari hal tersebut? Demi Allah sesungguhnya para isteri Nabi shallallahu 'alaihi wasallam juga biasa melakukan \"dialog alot dan debat\" bersama beliau dan salah seorang dari mereka pada hari ini, bahkan meninggalkan beliau hingga malam hari. Umar berkata; maka aku katakan dalam hati; telah celaka orang yang melakukan hal tersebut diantara mereka, dan telah merugi dia. Umar berkata; rumahku ketika itu di perkampungan namanya 'Aliyah, diantara Bani Umayyah. Aku pernah memiliki seorang tetangga dari kalangan anshar, kami dahulu bergantian menemui Rasulullah shallallahu 'alaihi wasallam. Sehari ia datang kepadaku membawa berita wahyu, dan yang lainnya. Dan hari lain aku yang datang menemui beliau membawa yang semisal hal tersebut. Umar berkata; ketika itu kami sedang hangat-hangatnya menceritakan bahwa raja Ghassan memasang sepatu kuda untuk memerangi kami. Ia berkata; kemudian tetangga tersebut datang kepadaku pada malam hari, dan mengetuk pintu. Lalu aku keluar menemuinya, ia berkata; telah terjadi perkara besar. Aku katakan; apakah Ghassan telah datang? Ia berkata; lebih besar daripada hal itu. Rasulullah shallallahu 'alaihi wasallam telah mencerai para isterinya. Umar berkata; lalu aku mengatakan dalam hati; Hafshah telah celaka dan merugi, aku telah menyangka hal ini akan terjadi. Umar berkata; tatkala aku telah melakukan shalat Shubuh aku mengencangkan pakaianku kemudian pergi hingga menemui Hafshah. Ternyata ia sedang menangis, lalu aku bertanya; apakah Rasulullah shallallahu 'alaihi wasallam telah mencerai kalian? Ia berkata; saya tidak tahu, beliau sedang menyendiri di ruangan yang tinggi ini. Umar berkata; kemudian aku pergi dan mendatangi seorang budak hitam lalu aku katakan; mintakan izin untuk Umar. Lalu Umar masuk kemudian keluar menemuiku seraya berkata; aku telah menyebutkan dirimu namun beliau tidak mengatakan sesuatupun. Lalu aku pergi, tiba-tiba budak tersebut memanggilku dan mengatakan; masuklah! Sungguh engkau telah diberi izin. Maka akupun masuk, ternyata Nabi sedang bersandar kepada tikar dan aku melihat bekasnya pada sisi badan beliau, lalu aku katakan; wahai Rasulullah, apakah anda mencerai isteri-isteri anda? Beliau bersabda: \"Tidak\" Maka aku katakan; Allahu akbar, wahai Rasulullah sungguh aku melihat kita orang-orang Quraisy, dahulu menguasai para wanita, kemudian tatkala kita datang ke Madinah maka kita mendapatkan sebuah kaum yang dikuasai para isteri mereka, kemudian para isteri kita mulai belajar dari isteri-isteri mereka, lalu aku suatu hari marah kepada isteriku ternyata ia membantahku hingga aku mengingkari hal tersebut, lalu ia berkata; apa yang engkau ingkari? Demi Allah sesungguhnya para isteri Nabi shallallahu 'alaihi wasallam membantah beliau dan salah seorang dari mereka meninggalkan beliau pada hari ini hingga malam hari. Umar berkata; lalu aku berkata kepada Hafshah; apakah engkau membantah Rasulullah? Maka ia berkata; ya, dan salah seorang dari kami meninggalkan beliau hingga malam hari. Lalu saya katakan; telah celaka orang yang melakukan hal tersebut diantara kalian dan ia telah merugi, apakah salah seorang diantara kalian aman dari kemarahan Allah kepadanya karena kemarahan RasulNya? Ternyata ia telah bersedih. Kemudian Nabi shallallahu 'alaihi wasallam tersenyum. Umar berkata; kemudian aku berkata kepada Hafshah; janganlah engkau membantah Rasulullah shallallahu 'alaihi wasallam dan jangan meminta sesuatu kepada beliau, mintalah kepadaku apa yang engkau inginkan janganlah terpengaruh apabila sahabatmu lebih cantik dan lebih dicintai Rasulullah shallallahu 'alaihi wasallam. Umar berkata; kemudian beliau tersenyum lagi, lalu aku katakan; wahai Rasulullah, apakah saya boleh meminta izin untuk berbicara? Beliau mengatakan: \"Ya.\" Umar berkata; kemudian aku mengangkat kepala dan tidak ada yang aku lihat di dalam rumah kecuali tiga peralatan rumah tangga. Umar berkata; kemudian aku katakan; wahai Rasulullah, berdoalah agar Allah memberikan kelapangan kepada umatmu, sungguh Allah telah memberikan kelapangan kepada orang-orang Persia dan Romawi sementara mereka tidak beribadah kepadaNya. Kemudian beliau duduk tegak, dan berkata: \"Apakah engkau merasa ragu wahai Ibnu Al Khathab? Mereka adalah orang-orang yang disegerakan kebaikan-kebaikan mereka dalam kehidupan dunia.\" Umar berkata; beliau telah bersumpah untuk tidak menemui para isterinya selama satu bulan, kemudian Allah mencelanya dalam hal tersebut dan mengharuskan beliau untuk membayar kafarah karena sebuah sumpah. [Az Zuhri] berkata; telah mengabarkan kepadaku ['Urwah] dari [Aisyah], ia berkata; kemudian tatkala telah berlalu dua puluh sembilan hari, Nabi shallallahu 'alaihi wasallam menemuiku dan memulai dariku. Beliau berkata: \"Wahai Aisyah, sesungguhnya aku menyebutkan sesuatu kepadamu dan janganlah engkau terburu-buru hingga engkau meminta pertimbangan kedua orang tuamu.\" Aisyah berkata; kemudian beliau membacakan ayat ini: Hai Nabi, katakanlah kepada isteri-isterimu: \"Jika kamu sekalian mengingini kehidupan dunia dan perhiasannya, maka marilah supaya kuberikan kepadamu mut'ah dan aku ceraikan kamu dengan cara yang baik. (QS. Al-Ahzab 28), Demi Allah beliau telah mengetahui bahwa kedua orang tuaku tidak memerintahkanku untuk berpisah dengannya. Lalu aku katakan; apakah dalam hal ini saya harus meminta pertimbangan kedua orang tuaku? Sesungguhnya saya menginginkan Allah dan rasulNya serta kampung akherat. [Ma'mar] berkata; dan telah mengabarkan kepada kami [Ayyub] bahwa [Aisyah] berkata kepada beliau; wahai Rasulullah, janganlah engkau memberitahu isteri-isterimu bahwa saya memilihmu. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku diutus Allah untuk menyampaikan dan Allah tidak mengutusku untuk mempersulit.\" Abu Isa berkata; hadits ini adalah hadits hasan shahih gharib, dan tealh diriwayatkan tidak hanya dari satu sisi dari Ibnu Abbas."}],"66:5":[{"p":"Bukhari","n":3818,"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُوَافَقْتُ اللَّهَ فِي ثَلَاثٍ أَوْ وَافَقَنِي رَبِّي فِي ثَلَاثٍ قُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْتَ مَقَامَ إِبْرَاهِيمَ مُصَلًّى وَقُلْتُ يَا رَسُولَ اللَّهِ يَدْخُلُ عَلَيْكَ الْبَرُّ وَالْفَاجِرُ فَلَوْ أَمَرْتَ أُمَّهَاتِ الْمُؤْمِنِينَ بِالْحِجَابِ فَأَنْزَلَ اللَّهُ آيَةَ الْحِجَابِ قَالَ وَبَلَغَنِي مُعَاتَبَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْضَ نِسَائِهِ فَدَخَلْتُ عَلَيْهِنَّ قُلْتُ إِنْ انْتَهَيْتُنَّ أَوْ لَيُبَدِّلَنَّ اللَّهُ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرًا مِنْكُنَّ حَتَّى أَتَيْتُ إِحْدَى نِسَائِهِ قَالَتْ يَا عُمَرُ أَمَا فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَعِظُ نِسَاءَهُ حَتَّى تَعِظَهُنَّ أَنْتَ فَأَنْزَلَ اللَّهُ{ عَسَى رَبُّهُ إِنْ طَلَّقَكُنَّ أَنْ يُبَدِّلَهُ أَزْوَاجًا خَيْرًا مِنْكُنَّ مُسْلِمَاتٍ }الْآيَةَوَقَالَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي حُمَيْدٌ سَمِعْتُ أَنَسًا عَنْ عُمَرَ","trj":"Telah menceritakan kepada kami [Musaddad] dari [Yahya bin Sa'id] dari [Humaid] dari [Anas] dia berkata; ['Umar] berkata; Aku telah menepati Rabbku dalam tiga hal, atau Rabbku telah menyetujuiku dalam tiga hal. Aku berkata; \"Wahai Rasulullah seandainya engkau menjadikan Maqam Ibrahim sebagai tempat shalat.\" Aku berkata; \"Wahai Rasulullah, sesungguhnya yang menemuimu adalah orang-orang yang baik dan yang jahat, seandainya engkau perintahkan kepada para Ummul Mukminin supaya memakai hijab.\" maka turunlah ayat hijab. Dan suatu ketika aku mendengar Rasulullah shallallahu 'alaihi wasallam mempersalahkan sebagian istri-istrinya, maka akupun mengunjungi mereka dan berkata; \"Berhentilah kalian dari berbuat masalah dengan Nabi atau boleh jadi Allah akan memberi ganti kepadanya dengan isteri yang lebih baik dari pada kalian.\" Ketika aku menemui salah seorang istrinya, ia berkata kepadaku; wahai Umar! Bukankah Rasulullah shallallahu 'alaihi wasallam lebih berhak menasihati istri-istrinya daripada kamu? Maka turunlah ayat; \"Boleh jadi jika ia ceraikan kamu, Tuhannya akan memberinya ganti istri-istri yang lebih baik dari pada kamu -perempuan yang berserah diri.- (QS At Tahrim: 5).\" Dan [Ibnu Abu Maryam] berkata; Telah mengabarkan kepada kami [Yahya bin Ayub] Telah menceritakan kepadaku [Humaid] Aku mendengar [Anas] dari [Umar]."}]},"mapping_surah":[{"p":"Bukhari","n":2288,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمْ أَزَلْ حَرِيصًا عَلَى أَنْ أَسْأَلَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }فَحَجَجْتُ مَعَه فَعَدَلَ وَعَدَلْتُ مَعَهُ بِالْإِدَاوَةِ فَتَبَرَّزَ حَتَّى جَاءَ فَسَكَبْتُ عَلَى يَدَيْهِ مِنْ الْإِدَاوَةِ فَتَوَضَّأَ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ الْمَرْأَتَانِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَانِ قَالَ اللَّهُ عَزَّ وَجَلَّ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }فَقَالَ وَا عَجَبِي لَكَ يَا ابْنَ عَبَّاسٍ عَائِشَةُ وَحَفْصَةُ ثُمَّ اسْتَقْبَلَ عُمَرُ الْحَدِيثَ يَسُوقُهُ فَقَالَ إِنِّي كُنْتُ وَجَارٌ لِي مِنْ الْأَنْصَارِ فِي بَنِي أُمَيَّةَ بْنِ زَيْدٍ وَهِيَ مِنْ عَوَالِي الْمَدِينَةِ وَكُنَّا نَتَنَاوَبُ النُّزُولَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْزِلُ يَوْمًا وَأَنْزِلُ يَوْمًا فَإِذَا نَزَلْتُ جِئْتُهُ مِنْ خَبَرِ ذَلِكَ الْيَوْمِ مِنْ الْأَمْرِ وَغَيْرِهِ وَإِذَا نَزَلَ فَعَلَ مِثْلَهُ وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا عَلَى الْأَنْصَارِ إِذَا هُمْ قَوْمٌ تَغْلِبُهُمْ نِسَاؤُهُمْ فَطَفِقَ نِسَاؤُنَا يَأْخُذْنَ مِنْ أَدَبِ نِسَاءِ الْأَنْصَارِ فَصِحْتُ عَلَى امْرَأَتِي فَرَاجَعَتْنِي فَأَنْكَرْتُ أَنْ تُرَاجِعَنِي فَقَالَتْ وَلِمَ تُنْكِرُ أَنْ أُرَاجِعَكَ فَوَاللَّهِ إِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ليُرَاجِعْنَهُ وَإِنَّ إِحْدَاهُنَّ لَتَهْجُرُهُ الْيَوْمَ حَتَّى اللَّيْلِ فَأَفْزَعَنِي فَقُلْتُ خَابَتْ مَنْ فَعَلَ مِنْهُنَّ بِعَظِيمٍ ثُمَّ جَمَعْتُ عَلَيَّ ثِيَابِي فَدَخَلْتُ عَلَى حَفْصَةَ فَقُلْتُ أَيْ حَفْصَةُ أَتُغَاضِبُ إِحْدَاكُنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَوْمَ حَتَّى اللَّيْلِ فَقَالَتْ نَعَمْ فَقُلْتُ خَابَتْ وَخَسِرَتْ أَفَتَأْمَنُ أَنْ يَغْضَبَ اللَّهُ لِغَضَبِ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَهْلِكِينَ لَا تَسْتَكْثِرِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تُرَاجِعِيهِ فِي شَيْءٍ وَلَا تَهْجُرِيهِ وَاسْأَلِينِي مَا بَدَا لَكِ وَلَا يَغُرَّنَّكِ أَنْ كَانَتْ جَارَتُكَ هِيَ أَوْضَأَ مِنْكِ وَأَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عَائِشَةَ وَكُنَّا تَحَدَّثْنَا أَنَّ غَسَّانَ تُنْعِلُ النِّعَالَ لِغَزْوِنَا فَنَزَلَ صَاحِبِي يَوْمَ نَوْبَتِهِ فَرَجَعَ عِشَاءً فَضَرَبَ بَابِي ضَرْبًا شَدِيدًا وَقَالَ أَنَائِمٌ هُوَ فَفَزِعْتُ فَخَرَجْتُ إِلَيْهِ وَقَالَ حَدَثَ أَمْرٌ عَظِيمٌ قُلْتُ مَا هُوَ أَجَاءَتْ غَسَّانُ قَالَ لَا بَلْ أَعْظَمُ مِنْهُ وَأَطْوَلُ طَلَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ قَالَ قَدْ خَابَتْ حَفْصَةُ وَخَسِرَتْ كُنْتُ أَظُنُّ أَنَّ هَذَا يُوشِكُ أَنْ يَكُونَ فَجَمَعْتُ عَلَيَّ ثِيَابِي فَصَلَّيْتُ صَلَاةَ الْفَجْرِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ مَشْرُبَةً لَهُ فَاعْتَزَلَ فِيهَا فَدَخَلْتُ عَلَى حَفْصَةَ فَإِذَا هِيَ تَبْكِي قُلْتُ مَا يُبْكِيكِ أَوَلَمْ أَكُنْ حَذَّرْتُكِ أَطَلَّقَكُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَا أَدْرِي هُوَ ذَا فِي الْمَشْرُبَةِ فَخَرَجْتُ فَجِئْتُ الْمِنْبَرَ فَإِذَا حَوْلَهُ رَهْطٌ يَبْكِي بَعْضُهُمْ فَجَلَسْتُ مَعَهُمْ قَلِيلًا ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ الْمَشْرُبَةَ الَّتِي هُوَ فِيهَا فَقُلْتُ لِغُلَامٍ لَهُ أَسْوَدَ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ فَكَلَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ خَرَجَ فَقَالَ ذَكَرْتُكَ لَهُ فَصَمَتَ فَانْصَرَفْتُ حَتَّى جَلَسْتُ مَعَ الرَّهْطِ الَّذِينَ عِنْدَ الْمِنْبَرِ ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ فَذَكَرَ مِثْلَهُ فَجَلَسْتُ مَعَ الرَّهْطِ الَّذِينَ عِنْدَ الْمِنْبَرِ ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ الْغُلَامَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ فَذَكَرَ مِثْلَهُ فَلَمَّا وَلَّيْتُ مُنْصَرِفًا فَإِذَا الْغُلَامُ يَدْعُونِي قَالَ أَذِنَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلْتُ عَلَيْهِ فَإِذَا هُوَ مُضْطَجِعٌ عَلَى رِمَالِ حَصِيرٍ لَيْسَ بَيْنَهُ وَبَيْنَهُ فِرَاشٌ قَدْ أَثَّرَ الرِّمَالُ بِجَنْبِهِ مُتَّكِئٌ عَلَى وِسَادَةٍ مِنْ أَدَمٍ حَشْوُهَا لِيفٌ فَسَلَّمْتُ عَلَيْهِ ثُمَّ قُلْتُ وَأَنَا قَائِمٌ طَلَّقْتَ نِسَاءَكَ فَرَفَعَ بَصَرَهُ إِلَيَّ فَقَالَ لَا ثُمَّ قُلْتُ وَأَنَا قَائِمٌ أَسْتَأْنِسُ يَا رَسُولَ اللَّهِ لَوْ رَأَيْتَنِي وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا عَلَى قَوْمٍ تَغْلِبُهُمْ نِسَاؤُهُمْ فَذَكَرَهُ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قُلْتُ لَوْ رَأَيْتَنِي وَدَخَلْتُ عَلَى حَفْصَةَ فَقُلْتُ لَا يَغُرَّنَّكِ أَنْ كَانَتْ جَارَتُكِ هِيَ أَوْضَأَ مِنْكِ وَأَحَبَّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عَائِشَةَ فَتَبَسَّمَ أُخْرَى فَجَلَسْتُ حِينَ رَأَيْتُهُ تَبَسَّمَ ثُمَّ رَفَعْتُ بَصَرِي فِي بَيْتِهِ فَوَاللَّهِ مَا رَأَيْتُ فِيهِ شَيْئًا يَرُدُّ الْبَصَرَ غَيْرَ أَهَبَةٍ ثَلَاثَةٍ فَقُلْتُ ادْعُ اللَّهَ فَلْيُوَسِّعْ عَلَى أُمَّتِكَ فَإِنَّ فَارِسَ وَالرُّومَ وُسِّعَ عَلَيْهِمْ وَأُعْطُوا الدُّنْيَا وَهُمْ لَا يَعْبُدُونَ اللَّهَ وَكَانَ مُتَّكِئًا فَقَالَ أَوَفِي شَكٍّ أَنْتَ يَا ابْنَ الْخَطَّابِ أُولَئِكَ قَوْمٌ عُجِّلَتْ لَهُمْ طَيِّبَاتُهُمْ فِي الْحَيَاةِ الدُّنْيَا فَقُلْتُ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ لِي فَاعْتَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَجْلِ ذَلِكَ الْحَدِيثِ حِينَ أَفْشَتْهُ حَفْصَةُ إِلَى عَائِشَةَ وَكَانَ قَدْ قَالَ مَا أَنَا بِدَاخِلٍ عَلَيْهِنَّ شَهْرًا مِنْ شِدَّةِ مَوْجِدَتِهِ عَلَيْهِنَّ حِينَ عَاتَبَهُ اللَّهُ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ دَخَلَ عَلَى عَائِشَةَ فَبَدَأَ بِهَا فَقَالَتْ لَهُ عَائِشَةُ إِنَّكَ أَقْسَمْتَ أَنْ لَا تَدْخُلَ عَلَيْنَا شَهْرًا وَإِنَّا أَصْبَحْنَا لِتِسْعٍ وَعِشْرِينَ لَيْلَةً أَعُدُّهَا عَدًّا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ وَكَانَ ذَلِكَ الشَّهْرُ تِسْعًا وَعِشْرِينَ قَالَتْ عَائِشَةُ فَأُنْزِلَتْ آيَةُ التَّخْيِيرِ فَبَدَأَ بِي أَوَّلَ امْرَأَةٍ فَقَالَ إِنِّي ذَاكِرٌ لَكِ أَمْرًا وَلَا عَلَيْكِ أَنْ لَا تَعْجَلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ قَدْ أَعْلَمُ أَنَّ أَبَوَيَّ لَمْ يَكُونَا يَأْمُرَانِي بِفِرَاقِكَ ثُمَّ قَالَ إِنَّ اللَّهَ قَالَ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ إِلَى قَوْلِهِ عَظِيمًا }قُلْتُ أَفِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ ثُمَّ خَيَّرَ نِسَاءَهُ فَقُلْنَ مِثْلَ مَا قَالَتْ عَائِشَةُ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku ['Ubaidullah bin 'Abdullah bin Abu Tsaur] dari ['Abdullah bin 'Abbas radliallahu 'anhuma] berkata: \"Aku selalu antusias untuk bertanya kepada ['Umar] tentang dua wanita diantara isteri-isteri Nabi shallallahu 'alaihi wasallam yang Allah berfirman kepada keduanya: (\"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan) …QS At-Tahrim 4). Maka aku kunjungi dia namun dia menghindar dan aku susul dia dengan membawa kantong terbuat dari kulit berisi air hingga dia datang, lalu aku tuangkan air dari kantong air tadi keatas kedua tangannya hingga dia berwudhu' lalu aku tanya: \"Wahai amirul mu'minin, siapakah dua wanita dari isteri Nabi shallallahu 'alaihi wasallam yang Allah berfirman kepadanya (\"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan) …), maka dia menjawab: \"Aku heran kepadamu wahai Ibnu 'Abbas!, dia adalah 'Aisyah dan Hafshah\". Kemudian 'Umar menyebutkan hadits, katanya: \"Aku dan tetanggaku dari Anshar berada di desa Banu Umayyah bin Zaid, termasuk suku kepercayaan di Madinah dan kami saling bergantian menemui Rasul shallallahu 'alaihi wasallam. Sehari aku yang menemui Beliau shallallahu 'alaihi wasallam, hari lain dia yang menemui Beliau shallallahu 'alaihi wasallam. Jika giliranku menemui Beliau, aku menanyakan seputar wahyu yang turun hari itu dan perkara lainnya. Dan jika giliran tetangguku itu, ia pun melakukan hal sama. Kami adalah kaum Quraisy yang bisa menundukkan para isteri, hingga ketika kami mendatangi Kaum Anshar, ternyata mereka adalah sebuah kaum yang ditundukkan oleh isteri-isteri mereka. Lalu isteri-isteri kami segera saja meniru kebiasaan wanita Anshar tersebut. Suatu hari aku nasehati isteriku tapi dia membantahku dan aku larang dia membantahku tapi dia berkata: \"Kenapa kamu melarang aku membantahmu? Demi Allah, sesungguhnya hari ini isteri-isteri Nabi Shallallahu 'alaihiwasallam telah membantah Beliau bahkan seorang dari mereka tidak berbicara kepada Beliau hingga malam hari\". Aku kaget mendengar itu lalu aku katakan: \"Sangat celakalah diantara kalian orang yang berbuat hal seperti ini\". Kemudian aku bergegas untuk menemui Hafshah lalu aku bertanya: \"Wahai Hafshah, apakah salah seorang dari kalian hari ini telah membantah Rasulullah shallallahu 'alaihi wasallam hingga malam hari?\" Dia menjawab: \"Iya\". Aku katakan: \"Celaka dan rugilah. Apakah kalian merasa aman dari murka Allah disebabkan RasulNya shallallahu 'alaihi wasallam marah lalu kalian menjadi binasa? Janganlah kalian menuntut terlalu banyak kepada Rasulullah shallallahu 'alaihi wasallam dan jangan kalian membantahnya tentang suatu apapun dan jangan pula kalian menghindar untuk berbicara dengan Beliau. Mintalah kepadaku apa yang menjadi keperluanmu dan jangan kamu cemburu bila ada (isteri Nabi shallallahu 'alaihi wasallam), madu kamu, yang lebih cantik dan lebih dicintai oleh Rasulullah shallallahu 'alaihi wasallam \". Yang dimaksudkannya adalah 'Aisyah radliallahu 'anha. Suatu hari kami membicarakan suku Ghossan sebagai tukang sepatu yang biasanya menyiapkan sepatu kami untuk perang. Maka sahabatku pergi (menemui Rasulullah shallallahu 'alaihi wasallam) pada hari gilirannya lalu dia kembali pada waktu 'Isya dengan mengetuk rumahku dengan sangat keras seraya berkata: \"Apakah dia sudah tidur?\" Aku kaget lalu keluar menemuinya. Dia berkata: \"Telah terjadi masalah besar\". Aku bertanya: \"Masalah apa itu? Apakah suku Ghassan sudah datang?\" Dia menjawab: \"Bukan, bahkan urusannya lebih penting dan lebih panjang dari masalah itu. Rasulullah shallallahu 'alaihi wasallam telah menceraikan isteri-isteri Beliau. 'Umar berkata: \"Sungguh celaka dan rugilah Hafshah. Aku mengira hal ini tidak akan terjadi. Maka aku lipat pakaianku kemudian aku shalat Shubuh bersama Nabi shallallahu 'alaihi wasallam lalu Beliau memasuki bilik yang tinggi dan mengasingkan diri disana. Maka aku menemui Hafshah yang ternyata sedang menangis lalu aku bertanya: \"Apa yang membuatmu menangis, bukankah aku sudah peringatkan kamu? Apakah Rasulullah shallallahu 'alaihi wasallam telah menceraikan kalian?\" Dia menjawab: \"Aku tidak tahu, sekarang Beliau berada di tempat pengasingannya\". Maka aku keluar lalu mendatangi mimbar ternyata di sekelilingnya ada sejumlah orang (kurang dari sepuluh) yang sedang berkumpul diantaranya ada yang menangis. Maka aku duduk bersama mereka sebentar lalu aku sangat ingin mendatangi tempat pengasingan tempat Beliau berdiam disana. Aku katakan kepada Aswad, anak kecil pembantu Beliau: \"Mintakanlah izin untuk 'Umar?\" Maka dia masuk dan berbicara dengan Nabi shallallahu 'alaihi wasallam lalu keluar dan berkata: \"Aku sudah sampaikan tentang maksudmu namun Beliau diam saja\". Maka kemudian aku kembali dan berkumpul bersama orang-orang yang berada dekat mimbar. Sesaat kemudian timbul lagi keinginanku maka aku temui anak kecil itu lalu aku sampaikan maksudku seperti tadi dan diapun menjawab seperti tadi pula. Maka aku kembali duduk bersama orang-orang yang berada dekat mimbar. Ternyata timbul lagi keinginanku, maka aku datangi lagi anak kecil itu dan aku katakan: \"Mintakanlah izin untuk 'Umar?\" Maka dia menjawab seperti tadi pula. Ketika aku hendak kembali, anak kecil itu memanggilku dan berkata: \"Rasulullah shallallahu 'alaihi wasallam mengizinkan kamu masuk\". Maka aku masuk menemui Beliau yang ketika itu Beliau sedang berbaring diatas pasir sebagai kasurnya, dan tidak ada kasur yang menengahi antara pasir dan beliau sehingga pasir itu membekas pada sisi badan Beliau, Beliau bersandar diatas bantal yang terbuat dari kulit yang isinya sabut. Aku memberi salam kepada Beliau lalu aku berkata dalam posisi tetap berdiri: \"Apakah anda telah menceraikan isteri-isteri anda\". Maka Beliau memandang ke arahku lalu berkata: \"Tidak\". Kemudian aku katakan: \"Apakah anda merasa tidak enak karena melihat aku?\" Kami ini adalah orang Quraisy yang biasa menundukkan isteri-isteri. Ketika kami datang disini bertemu dengan Kaum yang mereka ditundukkan oleh isteri-isteri mereka\". Maka 'Umar menceritakan. Lalu Nabi shallallahu 'alaihi wasallam tersenyum. Kemudian aku katakan: \"Bagaimana seandainya anda melihatku menemui Hafshah dan aku katakan kepadanya: \"Jangan kamu cemburu bila ada (isteri Nabi shallallahu 'alaihi wasallam), madu kamu, yang lebih cantik dan lebih dicintai oleh Rasulullah shallallahu 'alaihi wasallam \". Yang dimaksudkan Umar adalah 'Aisyah radliallahu 'anha. Maka Beliau tersenyum lagi. Lalu aku duduk ketika melihat Beliau tersenyum lalu aku memandang ke rumah Beliau. Demi Allah, aku tidak melihat apapun disana, karena mataku bolak balik melihat tidak kurang dari tiga kali. Lalu aku katakan: \"Mintalah kepada Allah agar melapangkan dunia buat ummat anda karena bangsa Persia dan Ramawi saja dilapangkan dan diberikan dunia padahal mereka tidak menyembah Allah\". Saat itu Beliau sedang berbaring lalu berkata: \"Apakah kamu ragu wahai Ibnu Al Khaththob? Mereka itulah kaum yang telah disegerakan kebaikan mereka dalam kehidupan dunia ini\". Aku katakan: \"Wahai Rasulullah, mohonkanlah ampun buatku\". Ternyata disebabkan kalimatku seperti tadilah Rasulullah shallallahu 'alaihi wasallam mengasingkan diri ketika Hafshah menyampaikannya kepada 'Aisyah radliallahu 'anha. Sebelumnya Beliau telah berkata: Aku tidak akan tinggal bersama mereka selama satu bulan karena disebabkan kesalnya Beliau terhadap mereka setelah Allah menegur Beliau. Ketika telah berlalu masa selama dua puluh sembilan hari, yang pertama kali Beliau datangi adalah 'Aisyah. Maka 'Aisyah berkata, kepada Beliau: \"Anda sudah bersumpah untuk tidak mendatangi kami selama satu bulan, sedangkan hari ini kita baru melewati malam kedua puluh sembilan, aku sudah menghitungnya\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Bulan ini berjumlah dua puluh sembilan hari\". Pada bulan itu memang berjumlah dua puluh sembilan hari. Kemudian 'Aisyah radliallahu 'anha berkata: \"Maka turunlah ayat takhyiir (pilihan). Maka Beliau memulainya dari aku sebagai yang pertama dari isteri-isteri Beliau. Beliau berkata: \"Sesungguhnya aku mengingatkan kamu pada suatu urusan yaitu janganlah kamu tergesa-gesa hingga kamu meminta pendapat kedua orangtuamu\". 'Aisyah radliallahu 'anha berkata: \"Aku sudah mengetahui bahwa kedua orangtuaku tidaklah menyuruh aku untuk bercerai dari anda\" Kemudian Beliau berkata: \"Sesungguhnya Allah telah berfirman: (\"Wahai Nabi, katakanlah kepada isteri-isterimu … hingga sampai pada firmanNya … pahala yang besar) QS Al Ahzab: 28 -29). Aisyah radliallahu 'anha berkata: \"Apakah begitu kedua orangtuaku memerintahkannya? Sungguh aku lebih memilih Allah, RasulNya dan kehidupan akhirat\". Kemudian para isteri Beliau memilih hal yang sama lalu mereka berkata, seperti yang diucapkan 'Aisyah radliallahu 'anha."},{"p":"Bukhari","n":3818,"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُوَافَقْتُ اللَّهَ فِي ثَلَاثٍ أَوْ وَافَقَنِي رَبِّي فِي ثَلَاثٍ قُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْتَ مَقَامَ إِبْرَاهِيمَ مُصَلًّى وَقُلْتُ يَا رَسُولَ اللَّهِ يَدْخُلُ عَلَيْكَ الْبَرُّ وَالْفَاجِرُ فَلَوْ أَمَرْتَ أُمَّهَاتِ الْمُؤْمِنِينَ بِالْحِجَابِ فَأَنْزَلَ اللَّهُ آيَةَ الْحِجَابِ قَالَ وَبَلَغَنِي مُعَاتَبَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْضَ نِسَائِهِ فَدَخَلْتُ عَلَيْهِنَّ قُلْتُ إِنْ انْتَهَيْتُنَّ أَوْ لَيُبَدِّلَنَّ اللَّهُ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرًا مِنْكُنَّ حَتَّى أَتَيْتُ إِحْدَى نِسَائِهِ قَالَتْ يَا عُمَرُ أَمَا فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَعِظُ نِسَاءَهُ حَتَّى تَعِظَهُنَّ أَنْتَ فَأَنْزَلَ اللَّهُ{ عَسَى رَبُّهُ إِنْ طَلَّقَكُنَّ أَنْ يُبَدِّلَهُ أَزْوَاجًا خَيْرًا مِنْكُنَّ مُسْلِمَاتٍ }الْآيَةَوَقَالَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي حُمَيْدٌ سَمِعْتُ أَنَسًا عَنْ عُمَرَ","trj":"Telah menceritakan kepada kami [Musaddad] dari [Yahya bin Sa'id] dari [Humaid] dari [Anas] dia berkata; ['Umar] berkata; Aku telah menepati Rabbku dalam tiga hal, atau Rabbku telah menyetujuiku dalam tiga hal. Aku berkata; \"Wahai Rasulullah seandainya engkau menjadikan Maqam Ibrahim sebagai tempat shalat.\" Aku berkata; \"Wahai Rasulullah, sesungguhnya yang menemuimu adalah orang-orang yang baik dan yang jahat, seandainya engkau perintahkan kepada para Ummul Mukminin supaya memakai hijab.\" maka turunlah ayat hijab. Dan suatu ketika aku mendengar Rasulullah shallallahu 'alaihi wasallam mempersalahkan sebagian istri-istrinya, maka akupun mengunjungi mereka dan berkata; \"Berhentilah kalian dari berbuat masalah dengan Nabi atau boleh jadi Allah akan memberi ganti kepadanya dengan isteri yang lebih baik dari pada kalian.\" Ketika aku menemui salah seorang istrinya, ia berkata kepadaku; wahai Umar! Bukankah Rasulullah shallallahu 'alaihi wasallam lebih berhak menasihati istri-istrinya daripada kamu? Maka turunlah ayat; \"Boleh jadi jika ia ceraikan kamu, Tuhannya akan memberinya ganti istri-istri yang lebih baik dari pada kamu -perempuan yang berserah diri.- (QS At Tahrim: 5).\" Dan [Ibnu Abu Maryam] berkata; Telah mengabarkan kepada kami [Yahya bin Ayub] Telah menceritakan kepadaku [Humaid] Aku mendengar [Anas] dari [Umar]."},{"p":"Nasa'i","n":2058,"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ حَدَّثَهُ ح و أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمْ أَزَلْ حَرِيصًا أَنْ أَسْأَلَ عُمَرَ بْنَ الْخَطَّابِ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }وَسَاقَ الْحَدِيثَ وَقَالَ فِيهِ فَاعْتَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ مِنْ أَجْلِ ذَلِكَ الْحَدِيثِ حِينَ أَفْشَتْهُ حَفْصَةُ إِلَى عَائِشَةَ تِسْعًا وَعِشْرِينَ لَيْلَةً قَالَتْ عَائِشَةُ وَكَانَ قَالَ مَا أَنَا بِدَاخِلٍ عَلَيْهِنَّ شَهْرًا مِنْ شِدَّةِ مَوْجِدَتِهِ عَلَيْهِنَّ حِينَ حَدَّثَهُ اللَّهُ عَزَّ وَجَلَّ حَدِيثَهُنَّ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ لَيْلَةً دَخَلَ عَلَى عَائِشَةَ فَبَدَأَ بِهَا فَقَالَتْ لَهُ عَائِشَةُ إِنَّكَ قَدْ كُنْتَ آلَيْتَ يَا رَسُولَ اللَّهِ أَنْ لَا تَدْخُلَ عَلَيْنَا شَهْرًا وَإِنَّا أَصْبَحْنَا مِنْ تِسْعٍ وَعِشْرِينَ لَيْلَةً نَعُدُّهَا عَدَدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ لَيْلَةً","trj":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami, dari [Shalih] dari [Ibnu Syihab] bahwasanya ['Ubaidullah bin 'Abdullah bin Abu Tsaur] menceritakan kepadanya. Demikian juga diriwayatkan dari jalur lain, dan telah mengabarkan kepada kami ['Amru bin Manshur] dia berkata; telah menceritakan kepada kami [Al Hakam bin Nafi'] dia berkata; telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin Abu Tsaur] dari [Ibnu 'Abbas] dia berkata; Aku masih tetap bersemangat untuk bertanya kepada [Umar bin Khaththab] tentang dua orang dari istri Rasulullah shallallahu 'alaihi wasallam yang Allah berfirman kepada keduanya: \"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong -untuk menerima kebaikan-.\" (Qs. At Tahrim 66: 4). Dan ia menyebutkan hadits ini. Ia berkata di dalam hadits tersebut; \"Maka Rasulullah shallallahu 'alaihi wasallam menjauh dari istri-istrinya karena pembicaraan itu; ketika Hafshah menyebarkannya kepada Aisyah, yaitu selama dua puluh Sembilan malam. Aisyah berkata; Beliau bersabda: \"Aku tidak akan menemui mereka selama satu bulan.\" Karena besarnya kemarahan beliau terhadap mereka, ketika Allah -Azza wa Jalla- menceritakan kepada beliau apa yang terjadi pada mereka. Setelah dua puluh Sembilan malam berlalu, beliau masuk menemui Aisyah, dan dengannyalah beliau memulainya, kemudian Aisyah berkata kepada beliau; \"Sesungguhnya engkau telah bersumpah wahai Rasulullah shallallahu 'alaihi wasallam, untuk tidak menemui kami selama satu bulan, dan kami memasuki pagi hari dari dua puluh sembilan malam, kami menghitungnya dari awal, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu ada dua puluh sembilan malam.\""},{"p":"Tirmidzi","n":3069,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ قَال سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُلَمْ أَزَلْ حَرِيصًا أَنْ أَسْأَلَ عُمَرَ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ عَزَّ وَجَلَّ{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }حَتَّى حَجَّ عُمَرُ وَحَجَجْتُ مَعَهُ فَصَبَبْتُ عَلَيْهِ مِنْ الْإِدَاوَةِ فَتَوَضَّأَ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ الْمَرْأَتَانِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَانِ قَالَ اللَّهُ{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا وَإِنْ تَظَاهَرَا عَلَيْهِ فَإِنَّ اللَّهَ هُوَ مَوْلَاهُ }فَقَالَ لِي وَاعَجَبًا لَكَ يَا ابْنَ عَبَّاسٍ قَالَ الزُّهْرِيُّ وَكَرِهَ وَاللَّهِ مَا سَأَلَهُ عَنْهُ وَلَمْ يَكْتُمْهُ فَقَالَ هِيَ عَائِشَةُ وَحَفْصَةُ قَالَ ثُمَّ أَنْشَأَ يُحَدِّثُنِي الْحَدِيثَ فَقَالَ كُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا الْمَدِينَةَ وَجَدْنَا قَوْمًا تَغْلِبُهُمْ نِسَاؤُهُمْ فَطَفِقَ نِسَاؤُنَا يَتَعَلَّمْنَ مِنْ نِسَائِهِمْ فَتَغَضَّبْتُ عَلَى امْرَأَتِي يَوْمًا فَإِذَا هِيَ تُرَاجِعُنِي فَقَالَتْ مَا تُنْكِرُ مِنْ ذَلِكَ فَوَاللَّهِ إِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُرَاجِعْنَهُ وَتَهْجُرُهُ إِحْدَاهُنَّ الْيَوْمَ إِلَى اللَّيْلِ قَالَ فَقُلْتُ فِي نَفْسِي قَدْ خَابَتْ مَنْ فَعَلَتْ ذَلِكَ مِنْهُنَّ وَخَسِرَتْ قَالَ وَكَانَ مَنْزِلِي بِالْعَوَالِي فِي بَنِي أُمَيَّةَ وَكَانَ لِي جَارٌ مِنْ الْأَنْصَارِ كُنَّا نَتَنَاوَبُ النُّزُولَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْزِلُ يَوْمًا فَيَأْتِينِي بِخَبَرِ الْوَحْيِ وَغَيْرِهِ وَأَنْزِلُ يَوْمًا فَآتِيهِ بِمِثْلِ ذَلِكَ قَالَ وَكُنَّا نُحَدِّثُ أَنَّ غَسَّانَ تُنْعِلُ الْخَيْلَ لِتَغْزُوَنَا قَالَ فَجَاءَنِي يَوْمًا عِشَاءً فَضَرَبَ عَلَى الْبَابِ فَخَرَجْتُ إِلَيْهِ فَقَالَ حَدَثَ أَمْرٌ عَظِيمٌ قُلْتُ أَجَاءَتْ غَسَّانُ قَالَ أَعْظَمُ مِنْ ذَلِكَ طَلَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ قَالَ فَقُلْتُ فِي نَفْسِي قَدْ خَابَتْ حَفْصَةُ وَخَسِرَتْ قَدْ كُنْتُ أَظُنُّ هَذَا كَائِنًا قَالَ فَلَمَّا صَلَّيْتُ الصُّبْحَ شَدَدْتُ عَلَيَّ ثِيَابِي ثُمَّ انْطَلَقْتُ حَتَّى دَخَلْتُ عَلَى حَفْصَةَ فَإِذَا هِيَ تَبْكِي فَقُلْتُ أَطَلَّقَكُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَا أَدْرِي هُوَ ذَا مُعْتَزِلٌ فِي هَذِهِ الْمَشْرَبَةِ قَالَ فَانْطَلَقْتُ فَأَتَيْتُ غُلَامًا أَسْوَدَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ قَالَ فَدَخَلَ ثُمَّ خَرَجَ إِلَيَّ قَالَ قَدْ ذَكَرْتُكَ لَهُ فَلَمْ يَقُلْ شَيْئًا قَالَ فَانْطَلَقْتُ إِلَى الْمَسْجِدِ فَإِذَا حَوْلَ الْمِنْبَرِ نَفَرٌ يَبْكُونَ فَجَلَسْتُ إِلَيْهِمْ ثُمَّ غَلَبَنِي مَا أَجِدُ فَأَتَيْتُ الْغُلَامَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ ثُمَّ خَرَجَ إِلَيَّ فَقَالَ قَدْ ذَكَرْتُكَ لَهُ فَلَمْ يَقُلْ شَيْئًا قَالَ فَانْطَلَقْتُ إِلَى الْمَسْجِدِ أَيْضًا فَجَلَسْتُ ثُمَّ غَلَبَنِي مَا أَجِدُ فَأَتَيْتُ الْغُلَامَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ ثُمَّ خَرَجَ إِلَيَّ فَقَالَ قَدْ ذَكَرْتُكَ لَهُ فَلَمْ يَقُلْ شَيْئًا قَالَ فَوَلَّيْتُ مُنْطَلِقًا فَإِذَا الْغُلَامُ يَدْعُونِي فَقَالَ ادْخُلْ فَقَدْ أُذِنَ لَكَ فَدَخَلْتُ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئٌ عَلَى رَمْلِ حَصِيرٍ قَدْ رَأَيْتُ أَثَرَهُ فِي جَنْبَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَطَلَّقْتَ نِسَاءَكَ قَالَ لَا قُلْتُ اللَّهُ أَكْبَرُ لَقَدْ رَأَيْتُنَا يَا رَسُولَ اللَّهِ وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا الْمَدِينَةَ وَجَدْنَا قَوْمًا تَغْلِبُهُمْ نِسَاؤُهُمْ فَطَفِقَ نِسَاؤُنَا يَتَعَلَّمْنَ مِنْ نِسَائِهِمْ فَتَغَضَّبْتُ يَوْمًا عَلَى امْرَأَتِي فَإِذَا هِيَ تُرَاجِعُنِي فَأَنْكَرْتُ ذَلِكَ فَقَالَتْ مَا تُنْكِرُ فَوَاللَّهِ إِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُرَاجِعْنَهُ وَتَهْجُرُهُ إِحْدَاهُنَّ الْيَوْمَ إِلَى اللَّيْلِ قَالَ فَقُلْتُ لِحَفْصَةَ أَتُرَاجِعِينَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ نَعَمْ وَتَهْجُرُهُ إِحْدَانَا الْيَوْمَ إِلَى اللَّيْلِ فَقُلْتُ قَدْ خَابَتْ مَنْ فَعَلَتْ ذَلِكَ مِنْكُنَّ وَخَسِرَتْ أَتَأْمَنُ إِحْدَاكُنَّ أَنْ يَغْضَبَ اللَّهُ عَلَيْهَا لِغَضَبِ رَسُولِهِ فَإِذَا هِيَ قَدْ هَلَكَتْ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقُلْتُ لِحَفْصَةَ لَا تُرَاجِعِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تَسْأَلِيهِ شَيْئًا وَسَلِينِي مَا بَدَا لَكِ وَلَا يَغُرَّنَّكِ إِنْ كَانَتْ صَاحِبَتُكِ أَوْسَمَ مِنْكِ وَأَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَتَبَسَّمَ أُخْرَى فَقُلْتُ يَا رَسُولَ اللَّهِ أَسْتَأْنِسُ قَالَ نَعَمْ قَالَ فَرَفَعْتُ رَأْسِي فَمَا رَأَيْتُ فِي الْبَيْتِ إِلَّا أُهُبَةً ثَلَاثَةً قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يُوَسِّعَ عَلَى أُمَّتِكَ فَقَدْ وَسَّعَ عَلَى فَارِسَ وَالرُّومِ وَهُمْ لَا يَعْبُدُونَهُ فَاسْتَوَى جَالِسًا فَقَالَ أَفِي شَكٍّ أَنْتَ يَا ابْنَ الْخَطَّابِ أُولَئِكَ قَوْمٌ عُجِّلَتْ لَهُمْ طَيِّبَاتُهُمْ فِي الْحَيَاةِ الدُّنْيَا قَالَ وَكَانَ أَقْسَمَ أَنْ لَا يَدْخُلَ عَلَى نِسَائِهِ شَهْرًا فَعَاتَبَهُ اللَّهُ فِي ذَلِكَ وَجَعَلَ لَهُ كَفَّارَةَ الْيَمِينِقَالَ الزُّهْرِيُّ فَأَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ قَالَتْ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ دَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَأَ بِي قَالَ يَا عَائِشَةُ إِنِّي ذَاكِرٌ لَكِ شَيْئًا فَلَا تَعْجَلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ }الْآيَةَ قَالَتْ عَلِمَ وَاللَّهِ أَنَّ أَبَوَيَّ لَمْ يَكُونَا يَأْمُرَانِي بِفِرَاقِهِ فَقُلْتُ أَفِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ قَالَ مَعْمَرٌ فَأَخْبَرَنِي أَيُّوبُ أَنَّ عَائِشَةَ قَالَتْ لَهُ يَا رَسُولَ اللَّهِ لَا تُخْبِرْ أَزْوَاجَكَ أَنِّي اخْتَرْتُكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا بَعَثَنِي اللَّهُ مُبَلِّغًا وَلَمْ يَبْعَثْنِي مُتَعَنِّتًا قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ ابْنِ عَبَّاسٍ","trj":"Telah menceritakan kepada kami [Abdu bin Humaid] telah mengabarkan kepada kami [Abdur Razzaq] dari [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abudullah bin Abu Tsaur], ia berkata; saya mendengar [Ibnu Abbas radliallahu 'anhuma] berkata; senantiasa aku bersemangat untuk bertanya kepada [Umar] mengenai dua orang wanita dari isteri-isteri Nabi shallallahu 'alaihi wasallam yang Allah dikatakan Allah 'azza wajalla: \"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan).\" (QS. Attahrim 4), Hingga Umar melakukan haji dan akupun berhaji bersamanya, kemudian aku menuangkan air dari tempat air untuk bersuci lalu ia berwudhu. Aku katakan; wahai amirul mukminin; siapakah dua orang wanita diantara isteri Nabi shallallahu 'alaihi wasallam yang Allah katakan: \"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan).\" (QS. Attahrim 4), Kemudian Umar berkata kepadaku; aneh engkau wahai Ibnu Abbas. Az Zuhri berkata; demi Allah ia tidak senang dengan apa yang ia tanyakan namun ia tidak menyembunyikannya. Ia berkata; ia adalah Aisyah dan Hafshah. Ibnu Abbas berkata; kemudian ia mulai menceritakan sebuah hadits kepadaku, ia berkata; dahulu kami orang-orang Quraisy menguasai para isteri, kemudian setelah kami datang ke Madinah kami mendapati orang-orang justru malah di atur para isteri mereka. Kemudian para isteri kami mulai belajar dari para isteri mereka, maka aku marah kepada isteriku pada suatu hari ternyata ia mendebatku dan berkata; apa yang engkau ingkari dari hal tersebut? Demi Allah sesungguhnya para isteri Nabi shallallahu 'alaihi wasallam juga biasa melakukan \"dialog alot dan debat\" bersama beliau dan salah seorang dari mereka pada hari ini, bahkan meninggalkan beliau hingga malam hari. Umar berkata; maka aku katakan dalam hati; telah celaka orang yang melakukan hal tersebut diantara mereka, dan telah merugi dia. Umar berkata; rumahku ketika itu di perkampungan namanya 'Aliyah, diantara Bani Umayyah. Aku pernah memiliki seorang tetangga dari kalangan anshar, kami dahulu bergantian menemui Rasulullah shallallahu 'alaihi wasallam. Sehari ia datang kepadaku membawa berita wahyu, dan yang lainnya. Dan hari lain aku yang datang menemui beliau membawa yang semisal hal tersebut. Umar berkata; ketika itu kami sedang hangat-hangatnya menceritakan bahwa raja Ghassan memasang sepatu kuda untuk memerangi kami. Ia berkata; kemudian tetangga tersebut datang kepadaku pada malam hari, dan mengetuk pintu. Lalu aku keluar menemuinya, ia berkata; telah terjadi perkara besar. Aku katakan; apakah Ghassan telah datang? Ia berkata; lebih besar daripada hal itu. Rasulullah shallallahu 'alaihi wasallam telah mencerai para isterinya. Umar berkata; lalu aku mengatakan dalam hati; Hafshah telah celaka dan merugi, aku telah menyangka hal ini akan terjadi. Umar berkata; tatkala aku telah melakukan shalat Shubuh aku mengencangkan pakaianku kemudian pergi hingga menemui Hafshah. Ternyata ia sedang menangis, lalu aku bertanya; apakah Rasulullah shallallahu 'alaihi wasallam telah mencerai kalian? Ia berkata; saya tidak tahu, beliau sedang menyendiri di ruangan yang tinggi ini. Umar berkata; kemudian aku pergi dan mendatangi seorang budak hitam lalu aku katakan; mintakan izin untuk Umar. Lalu Umar masuk kemudian keluar menemuiku seraya berkata; aku telah menyebutkan dirimu namun beliau tidak mengatakan sesuatupun. Lalu aku pergi, tiba-tiba budak tersebut memanggilku dan mengatakan; masuklah! Sungguh engkau telah diberi izin. Maka akupun masuk, ternyata Nabi sedang bersandar kepada tikar dan aku melihat bekasnya pada sisi badan beliau, lalu aku katakan; wahai Rasulullah, apakah anda mencerai isteri-isteri anda? Beliau bersabda: \"Tidak\" Maka aku katakan; Allahu akbar, wahai Rasulullah sungguh aku melihat kita orang-orang Quraisy, dahulu menguasai para wanita, kemudian tatkala kita datang ke Madinah maka kita mendapatkan sebuah kaum yang dikuasai para isteri mereka, kemudian para isteri kita mulai belajar dari isteri-isteri mereka, lalu aku suatu hari marah kepada isteriku ternyata ia membantahku hingga aku mengingkari hal tersebut, lalu ia berkata; apa yang engkau ingkari? Demi Allah sesungguhnya para isteri Nabi shallallahu 'alaihi wasallam membantah beliau dan salah seorang dari mereka meninggalkan beliau pada hari ini hingga malam hari. Umar berkata; lalu aku berkata kepada Hafshah; apakah engkau membantah Rasulullah? Maka ia berkata; ya, dan salah seorang dari kami meninggalkan beliau hingga malam hari. Lalu saya katakan; telah celaka orang yang melakukan hal tersebut diantara kalian dan ia telah merugi, apakah salah seorang diantara kalian aman dari kemarahan Allah kepadanya karena kemarahan RasulNya? Ternyata ia telah bersedih. Kemudian Nabi shallallahu 'alaihi wasallam tersenyum. Umar berkata; kemudian aku berkata kepada Hafshah; janganlah engkau membantah Rasulullah shallallahu 'alaihi wasallam dan jangan meminta sesuatu kepada beliau, mintalah kepadaku apa yang engkau inginkan janganlah terpengaruh apabila sahabatmu lebih cantik dan lebih dicintai Rasulullah shallallahu 'alaihi wasallam. Umar berkata; kemudian beliau tersenyum lagi, lalu aku katakan; wahai Rasulullah, apakah saya boleh meminta izin untuk berbicara? Beliau mengatakan: \"Ya.\" Umar berkata; kemudian aku mengangkat kepala dan tidak ada yang aku lihat di dalam rumah kecuali tiga peralatan rumah tangga. Umar berkata; kemudian aku katakan; wahai Rasulullah, berdoalah agar Allah memberikan kelapangan kepada umatmu, sungguh Allah telah memberikan kelapangan kepada orang-orang Persia dan Romawi sementara mereka tidak beribadah kepadaNya. Kemudian beliau duduk tegak, dan berkata: \"Apakah engkau merasa ragu wahai Ibnu Al Khathab? Mereka adalah orang-orang yang disegerakan kebaikan-kebaikan mereka dalam kehidupan dunia.\" Umar berkata; beliau telah bersumpah untuk tidak menemui para isterinya selama satu bulan, kemudian Allah mencelanya dalam hal tersebut dan mengharuskan beliau untuk membayar kafarah karena sebuah sumpah. [Az Zuhri] berkata; telah mengabarkan kepadaku ['Urwah] dari [Aisyah], ia berkata; kemudian tatkala telah berlalu dua puluh sembilan hari, Nabi shallallahu 'alaihi wasallam menemuiku dan memulai dariku. Beliau berkata: \"Wahai Aisyah, sesungguhnya aku menyebutkan sesuatu kepadamu dan janganlah engkau terburu-buru hingga engkau meminta pertimbangan kedua orang tuamu.\" Aisyah berkata; kemudian beliau membacakan ayat ini: Hai Nabi, katakanlah kepada isteri-isterimu: \"Jika kamu sekalian mengingini kehidupan dunia dan perhiasannya, maka marilah supaya kuberikan kepadamu mut'ah dan aku ceraikan kamu dengan cara yang baik. (QS. Al-Ahzab 28), Demi Allah beliau telah mengetahui bahwa kedua orang tuaku tidak memerintahkanku untuk berpisah dengannya. Lalu aku katakan; apakah dalam hal ini saya harus meminta pertimbangan kedua orang tuaku? Sesungguhnya saya menginginkan Allah dan rasulNya serta kampung akherat. [Ma'mar] berkata; dan telah mengabarkan kepada kami [Ayyub] bahwa [Aisyah] berkata kepada beliau; wahai Rasulullah, janganlah engkau memberitahu isteri-isterimu bahwa saya memilihmu. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku diutus Allah untuk menyampaikan dan Allah tidak mengutusku untuk mempersulit.\" Abu Isa berkata; hadits ini adalah hadits hasan shahih gharib, dan tealh diriwayatkan tidak hanya dari satu sisi dari Ibnu Abbas."}]};
